### SNIPPET 2: DesignStorage Save/Get Operations

```java
public class DesignStorage {
    private static final Map<String, DesignModel> designStore = new HashMap<>();

    // SAVE
    public boolean saveDesign(DesignModel design) {
        try {
            designStore.put(design.getDesignId(), design);
            System.out.println("[OK] Design saved: " + design.getDesignId());
            return true;
        } catch (Exception e) {
            System.err.println("[ERROR] Error saving: " + e.getMessage());
            return false;
        }
    }

    // GET BY USER ID (important for multi-user!)
    public List<DesignModel> getDesignsByUserId(String userId) {
        return designStore.values().stream()
            .filter(d -> d.getUserId().equals(userId))
            .collect(Collectors.toList());
    }

    // SEARCH BY NAME
    public List<DesignModel> searchByName(String userId, String searchTerm) {
        return designStore.values().stream()
            .filter(d -> d.getUserId().equals(userId))
            .filter(d -> d.getDesignName().toLowerCase()
                    .contains(searchTerm.toLowerCase()))
            .collect(Collectors.toList());
    }

    // DELETE
    public boolean deleteDesign(String designId) {
        try {
            designStore.remove(designId);
            System.out.println("[OK] Design deleted: " + designId);
            return true;
        } catch (Exception e) {
            System.err.println("[ERROR] Error deleting: " + e.getMessage());
            return false;
        }
    }
}
```

### SNIPPET 3: PortfolioPanel - Basic Setup

```java
public class PortfolioPanel extends JPanel {
    private DesignStorage designStorage;
    private String currentUserId;
    private JPanel gridPanel;

    public PortfolioPanel(Runnable onBackCallback, Runnable onLoadDesign) {
        this.designStorage = new DesignStorage();
        this.currentUserId = Session.getInstance().getCurrentUser().getUserId();

        initUI();
        loadUserDesigns();
    }

    private void initUI() {
        setLayout(new BorderLayout(15, 15));
        setBackground(new Color(245, 245, 245));

        // Add title
        JLabel title = new JLabel("Portfolio - My Designs");
        title.setFont(new Font("Segoe UI", Font.BOLD, 28));
        add(title, BorderLayout.NORTH);

        // Add grid
        gridPanel = new JPanel();
        gridPanel.setLayout(new GridLayout(0, 3, 15, 15)); // 3 columns
        JScrollPane scrollPane = new JScrollPane(gridPanel);
        add(scrollPane, BorderLayout.CENTER);
    }

    private void loadUserDesigns() {
        List<DesignModel> designs = designStorage.getDesignsByUserId(currentUserId);

        // Clear and re-render
        gridPanel.removeAll();
        for (DesignModel design : designs) {
            gridPanel.add(createDesignCard(design));
        }
        gridPanel.revalidate();
        gridPanel.repaint();
    }

    private JPanel createDesignCard(DesignModel design) {
        JPanel card = new JPanel();
        card.setLayout(new BoxLayout(card, BoxLayout.Y_AXIS));
        card.setBackground(Color.WHITE);

        // Add thumbnail
        JLabel thumb = new JLabel("No Preview");
        thumb.setPreferredSize(new Dimension(200, 150));
        card.add(thumb);

        // Add name
        JLabel nameLabel = new JLabel(design.getDesignName());
        nameLabel.setFont(new Font("Segoe UI", Font.BOLD, 13));
        card.add(nameLabel);

        // Add buttons
        JPanel btnPanel = new JPanel(new FlowLayout(FlowLayout.CENTER));

        JButton editBtn = new JButton("✏️ Edit");
        editBtn.addActionListener(e -> {
            JOptionPane.showMessageDialog(this, 
                "Loading: " + design.getDesignName());
            // TODO: Load design into editor
        });
        btnPanel.add(editBtn);

        JButton deleteBtn = new JButton("️ Delete");
        deleteBtn.addActionListener(e -> {
            int res = JOptionPane.showConfirmDialog(this, "Delete?");
            if (res == JOptionPane.YES_OPTION) {
                designStorage.deleteDesign(design.getDesignId());
                loadUserDesigns(); // Refresh
            }
        });
        btnPanel.add(deleteBtn);

        card.add(btnPanel);
        return card;
    }
}
```

