    }

    public void showEditor2D(com.teamname.furniviz.room.Room room) {
        designState.setRoom(room);
        editor2DPanel.setRoom(room);
        layout.show(this, "EDITOR_2D");
    }

    /**
     * Load a complete design (room + furniture) into the 2D editor
     * This is called from Portfolio when user clicks OPEN on a design
     */
    public void loadDesignForEditing(com.teamname.furniviz.storage.DesignModel design) {
        if (design == null || design.getRoom() == null) {
            System.err.println("[ERROR] Cannot load null design or design without room");
            return;
        }

        try {
            // Clear previous furniture items
            designState.clearFurnitureItems();

            // Load the room
            designState.setRoom(design.getRoom());
            editor2DPanel.setRoom(design.getRoom());

            // Load all furniture items from the design
            if (design.getFurnitureItems() != null) {
                for (com.teamname.furniviz.furniture.FurnitureItem item : design.getFurnitureItems()) {
                    designState.addFurnitureItem(item);
                }
            }

            // Notify all listeners that design state has changed
            designState.notifyListeners();

            System.out.println("[OK] Design loaded: " + design.getDesignName());
            System.out.println("[OK] Room: " + design.getRoom().getName() + 
                             " (" + design.getRoom().getWidth() + "m x " + design.getRoom().getLength() + "m)");
            System.out.println("[OK] Furniture items: " + 
                             (design.getFurnitureItems() != null ? design.getFurnitureItems().size() : 0));

            // Navigate to 2D editor
            layout.show(this, "EDITOR_2D");

        } catch (Exception e) {
            System.err.println("[ERROR] Error loading design: " + e.getMessage());
            e.printStackTrace();
        }
    }

    public void show3D() {
        if (view3DPanel != null) {
            view3DPanel.refresh();
        }
        layout.show(this, "VIEW_3D");
    }

    public void showPortfolio() {
        layout.show(this, "PORTFOLIO");
    }

    public void refreshPortfolio() {
        // Called when portfolio needs to be refreshed
        // (e.g., after loading a design from portfolio)
    }
}

package com.teamname.furniviz.common.util;

public class ValidationUtil {
    private static final String EMAIL_PATTERN = "^[A-Za-z0-9._%-]+@[A-Za-z0-9.-]+\\.[A-Za-z]{2,}$";

    public static boolean isValidEmail(String email) {
        if (email == null || email.isEmpty()) {
            return false;
        }
        return email.matches(EMAIL_PATTERN);
    }

    public static boolean isValidPassword(String password) {
        if (password == null || password.length() < 6) {
            return false;
        }

        boolean hasLetter = password.matches(".*[a-zA-Z].*");
        boolean hasDigit = password.matches(".*\\d.*");

        return hasLetter && hasDigit;
    }

    public static boolean isValidName(String name) {
        if (name == null || name.trim().isEmpty()) {
            return false;
        }
        return name.matches("^[a-zA-Z\\s\\-']+$") && name.trim().length() >= 2;
    }

    public static String sanitizeInput(String input) {
        if (input == null) {
            return "";
        }
        return input.trim();
    }

    public static String getEmailErrorMessage(String email) {
        if (email == null || email.isEmpty()) {
            return "Email is required";
        }
        if (!isValidEmail(email)) {
            return "Invalid email format";
        }
        return null;
    }

    public static String getPasswordErrorMessage(String password) {
        if (password == null || password.isEmpty()) {
            return "Password is required";
        }
        if (password.length() < 6) {
            return "Password must be at least 6 characters";
        }
        if (!password.matches(".*[a-zA-Z].*")) {
            return "Must contain a letter (a-z or A-Z)";
        }
        if (!password.matches(".*\\d.*")) {
            return "Must contain a number (0-9)";
        }
        return null;
    }

    public static String getNameErrorMessage(String name) {
        if (name == null || name.trim().isEmpty()) {
            return "Name is required";
        }
        if (name.trim().length() < 2) {
            return "Name must be at least 2 characters";
        }
        if (!isValidName(name)) {
            return "Name can only contain letters, spaces, hyphens, and apostrophes";
        }
        return null;
    }
}

package com.teamname.furniviz.common.util;

public class ValidationUtil {
    private static final String EMAIL_PATTERN = "^[A-Za-z0-9._+%-]+@[A-Za-z0-9.-]+\\.[A-Za-z]{2,}$";

    public static boolean isValidEmail(String email) {
        if (email == null || email.isEmpty()) {
            return false;
        }
        return email.matches(EMAIL_PATTERN);
    }

    public static boolean isValidPassword(String password) {
        if (password == null || password.length() < 6) {
            return false;
        }

        boolean hasLetter = password.matches(".*[a-zA-Z].*");
        boolean hasDigit = password.matches(".*\\d.*");

        return hasLetter && hasDigit;
    }

    public static boolean isValidName(String name) {
        if (name == null || name.trim().isEmpty()) {
            return false;
        }
        return name.matches("^[a-zA-Z\\s\\-']+$") && name.trim().length() >= 2;
    }

    public static String sanitizeInput(String input) {
        if (input == null) {
            return "";
        }
        return input.trim();
    }

    public static String getEmailErrorMessage(String email) {
        if (email == null || email.isEmpty()) {
            return "Email is required";
        }
        if (!isValidEmail(email)) {
            return "Invalid email format";
        }
        return null;
    }

    public static String getPasswordErrorMessage(String password) {
        if (password == null || password.isEmpty()) {
            return "Password is required";
        }
        if (password.length() < 6) {
            return "Password must be at least 6 characters";
        }
        if (!password.matches(".*[a-zA-Z].*")) {
            return "Must contain a letter (a-z or A-Z)";
        }
        if (!password.matches(".*\\d.*")) {
            return "Must contain a number (0-9)";
        }
        return null;
    }

    public static String getNameErrorMessage(String name) {
        if (name == null || name.trim().isEmpty()) {
            return "Name is required";
        }
        if (name.trim().length() < 2) {
            return "Name must be at least 2 characters";
        }
        if (!isValidName(name)) {
            return "Name can only contain letters, spaces, hyphens, and apostrophes";
        }
        return null;
    }
}

package com.teamname.furniviz.furniture;

import java.awt.Color;

/**
 * FurnitureItem - Represents a furniture instance placed in a room
 *
 * This is a concrete instance of furniture in the room design.
 * It includes position data (x, y) and can be transformed/moved.
 * Data-driven: the 3D renderer uses the type and dimensions to generate
 * the 3D shape, not PNG images.
 */
public class FurnitureItem {
    private String name;
    private FurnitureType type;
    private String imagePath; // Path to 2D preview image
    private double width;     // Width in meters
    private double height;    // Height in meters
    private double depth;     // Depth in meters
    private String material;
    private String description;
    private double x;         // X position in room (meters)
    private double y;         // Y position in room (meters)
    private double rotation;  // Rotation in degrees (0-360)
    private Color color;      // Color for 3D rendering

    public FurnitureItem(String name, FurnitureType type, String imagePath, double width, double height, double depth, String material, String description) {
        this.name = name;
        this.type = type;
        this.imagePath = imagePath;
        this.width = width;
        this.height = height;
        this.depth = depth;
        this.material = material;
        this.description = description;
        this.x = 0.0;
        this.y = 0.0;
        this.rotation = 0.0;
        this.color = new Color(150, 150, 150); // Default gray
    }

    // ============ Getters ============
    public String getName() { return name; }
    public FurnitureType getType() { return type; }
    public String getImagePath() { return imagePath; }
    public double getWidth() { return width; }
    public double getHeight() { return height; }
    public double getDepth() { return depth; }
    public String getMaterial() { return material; }
    public String getDescription() { return description; }
    public double getX() { return x; }
    public double getY() { return y; }
    public double getRotation() { return rotation; }
    public Color getColor() { return color; }

    // ============ Setters for position and transformation ============
    public void setPosition(double x, double y) {
        this.x = x;
        this.y = y;
    }

    public void setRotation(double degrees) {
        this.rotation = degrees % 360;
    }

    public void setWidth(double width) {
        this.width = Math.max(0.3, width); // Minimum 0.3 meters
    }

    public void setDepth(double depth) {
        this.depth = Math.max(0.3, depth); // Minimum 0.3 meters
    }

    public void setColor(Color color) {
        this.color = color;
    }

    @Override
    public String toString() {
        return name;
    }
}

