package com.teamname.furniviz.renderer3d;

import java.awt.Point;
import java.util.*;

/**
 * DepthSorter - Implements painter's algorithm for proper face rendering order
 *
 * Problem: Without depth sorting, faces render in random order causing z-fighting
 * Solution: Sort faces by depth (distance from camera) before rendering
 *
 * When faces are rendered back-to-front, closer faces appear on top of distant ones
 */
public class DepthSorter {

    /**
     * Represents a triangular face with depth information
     */
    public static class DepthFace implements Comparable<DepthFace> {
        public Point[] screenPoints;      // 2D projected screen coordinates
        public java.awt.Color fillColor;
        public java.awt.Color strokeColor;
        public float averageDepth;        // Average z-distance from camera

        public DepthFace(Point[] screenPoints, java.awt.Color fillColor, 
                        java.awt.Color strokeColor, float averageDepth) {
            this.screenPoints = screenPoints;
            this.fillColor = fillColor;
            this.strokeColor = strokeColor;
            this.averageDepth = averageDepth;
        }

        /**
         * Compare faces by depth (for sorting)
         * Returns faces sorted from BACK to FRONT (painter's algorithm)
         * Larger depth = farther away = should render first
         */
        @Override
        public int compareTo(DepthFace other) {
            // Sort in descending order (farthest first)
            return Float.compare(other.averageDepth, this.averageDepth);
        }
    }

    /**
     * Sort faces for proper rendering order
     */
    public static List<DepthFace> sortFacesByDepth(List<DepthFace> faces) {
        if (faces == null || faces.isEmpty()) {
            return faces;
        }

        // Create a copy and sort
        List<DepthFace> sorted = new ArrayList<>(faces);
        Collections.sort(sorted);
        return sorted;
    }

    /**
     * Calculate average depth of a face (distance from camera)
     * The face is defined by vertices in camera space
     */
    public static float calculateFaceDepth(Projection.Vector3f[] vertices) {
        if (vertices == null || vertices.length == 0) {
            return Float.MAX_VALUE;
        }

        float sumZ = 0;
        for (Projection.Vector3f v : vertices) {
            sumZ += v.z;
        }
        return sumZ / vertices.length;
    }

    /**
     * Calculate face depth for a triangle
     */
    public static float calculateTriangleDepth(
            Projection.Vector3f v1,
            Projection.Vector3f v2,
            Projection.Vector3f v3) {
        return (v1.z + v2.z + v3.z) / 3.0f;
    }

    /**
     * Calculate face center for sorting (alternative method)
     * Some systems use center instead of average
     */
    public static Projection.Vector3f calculateFaceCenter(Projection.Vector3f[] vertices) {
        if (vertices == null || vertices.length == 0) {
            return new Projection.Vector3f(0, 0, 0);
        }

        float sumX = 0, sumY = 0, sumZ = 0;
        for (Projection.Vector3f v : vertices) {
            sumX += v.x;
            sumY += v.y;
            sumZ += v.z;
        }

        int count = vertices.length;
        return new Projection.Vector3f(sumX / count, sumY / count, sumZ / count);
    }

    /**
     * Check if face is front-facing (normal points toward camera)
     * If not front-facing, it's backfacing and shouldn't be rendered
     */
    public static boolean isFrontFacing(
            Projection.Vector3f v1,
            Projection.Vector3f v2,
            Projection.Vector3f v3,
            Projection.Vector3f cameraPos) {

        // Calculate triangle normal
        Projection.Vector3f edge1 = v2.subtract(v1);
        Projection.Vector3f edge2 = v3.subtract(v1);
        Projection.Vector3f normal = edge1.cross(edge2);

        // Vector from triangle to camera
        Projection.Vector3f toCamera = cameraPos.subtract(v1);

        // If normal and toCamera point in same direction, face is front-facing
        return normal.dot(toCamera) > 0;
    }

    /**
     * Remove backfacing faces (optimization)
     * Faces that face away from camera don't need to be rendered
     */
    public static List<DepthFace> removeBackfacingFaces(
            List<DepthFace> faces,
            Projection.Vector3f cameraPos) {

        if (faces == null || faces.isEmpty()) {
            return faces;
        }

        List<DepthFace> frontFacing = new ArrayList<>();

        for (DepthFace face : faces) {
            if (face.screenPoints != null && face.screenPoints.length >= 3) {
                // Simple heuristic: if face area is positive, it's front-facing
                // (after projection, front-facing faces have positive area)
                double area = calculatePolygonArea(face.screenPoints);
                if (area > 0) {
                    frontFacing.add(face);
                }
            }
        }

        return frontFacing;
    }

    /**
     * Calculate 2D polygon area using Shoelace formula
     * Positive area = counter-clockwise = front-facing
     * Negative area = clockwise = back-facing
     */
    private static double calculatePolygonArea(Point[] points) {
        if (points == null || points.length < 3) {
            return 0;
        }

        double area = 0;
        for (int i = 0; i < points.length; i++) {
            Point p1 = points[i];
            Point p2 = points[(i + 1) % points.length];
            area += (double) p1.x * p2.y - (double) p2.x * p1.y;
        }

        return area / 2.0;
    }

    /**
     * Apply frustum culling - remove faces outside view frustum
     * This prevents rendering of geometry that's off-screen
     */
    public static List<DepthFace> applyCulling(
            List<DepthFace> faces,
            int screenWidth,
            int screenHeight) {

        if (faces == null) {
            return faces;
        }

        List<DepthFace> culled = new ArrayList<>();
        final int margin = 100;  // Allow some off-screen rendering

        for (DepthFace face : faces) {
            if (isInFrustum(face.screenPoints, screenWidth, screenHeight, margin)) {
                culled.add(face);
            }
        }

        return culled;
    }

    /**
     * Check if polygon is visible in screen bounds
     */
    private static boolean isInFrustum(Point[] points, int screenWidth, 
                                      int screenHeight, int margin) {
        if (points == null || points.length == 0) {
            return false;
        }

        for (Point p : points) {
            if (p.x >= -margin && p.x < screenWidth + margin &&
                p.y >= -margin && p.y < screenHeight + margin) {
                return true;
            }
        }

        return false;
    }
}

package com.teamname.furniviz.renderer3d;

import java.awt.Color;

/**
 * LightingManager - Manages lighting in the 3D scene
 *
 * Handles:
 * - Ambient lighting
 * - Directional lights
 * - Light color and intensity
 */
public class LightingManager {

    /**
     * Light - Represents a light source
     */
    public static class Light {
        public Projection.Vector3f position;     // Position in world space
        public Projection.Vector3f direction;    // Direction for directional lights
        public Color color;
        public float intensity;
        public LightType type;

        public enum LightType {
            AMBIENT,        // Uniform light everywhere
            DIRECTIONAL,    // Light from infinite distance (sun)
            POINT,          // Light from a point (bulb)
            SPOT            // Directional light from a point
        }

        public Light(LightType type, Color color, float intensity) {
            this.type = type;
            this.color = color;
            this.intensity = intensity;
            this.position = new Projection.Vector3f(0, 0, 0);
            this.direction = new Projection.Vector3f(0, -1, 0);  // Default: down
        }
    }

    private Light ambientLight;
    private Light directionalLight;

    /**
     * Default constructor - sets up standard lighting
     */
    public LightingManager() {
        // Ambient light: soft white light everywhere
        ambientLight = new Light(
            Light.LightType.AMBIENT,
            Color.WHITE,
            0.5f  // 50% ambient
        );

        // Directional light: sun-like light from top-left
        directionalLight = new Light(
            Light.LightType.DIRECTIONAL,
            Color.WHITE,
            0.8f  // 80% intensity
        );
        directionalLight.direction = new Projection.Vector3f(-1, -1, -1).normalize();
    }

    // ============================================================================
    // GETTERS/SETTERS
    // ============================================================================

    public Light getAmbientLight() { return ambientLight; }
    public Light getDirectionalLight() { return directionalLight; }

    public void setAmbientLight(Color color, float intensity) {
        ambientLight.color = color;
        ambientLight.intensity = Math.max(0, Math.min(1, intensity));
    }

    public void setDirectionalLight(Projection.Vector3f direction, Color color, float intensity) {
        directionalLight.direction = direction.normalize();
        directionalLight.color = color;
        directionalLight.intensity = Math.max(0, Math.min(1, intensity));
    }

    // ============================================================================
    // LIGHTING CALCULATIONS
    // ============================================================================

    /**
     * Calculate lighting intensity at a point given a normal
     * Uses simple Phong-like lighting model
     */
    public float calculateLightIntensity(Projection.Vector3f normal, Projection.Vector3f toLight) {
        // Ensure normal and light direction are normalized
        Projection.Vector3f n = normal.normalize();
        Projection.Vector3f l = toLight.normalize();

        // Lambert's cosine law
        float diffuse = Math.max(0, n.dot(l));

        return diffuse;
    }

    /**
     * Calculate final color given material color and lighting
     */
    public java.awt.Color calculateFinalColor(java.awt.Color materialColor,
                                              Projection.Vector3f normal,
                                              Projection.Vector3f toLight) {
        // Calculate diffuse lighting
        float intensity = calculateLightIntensity(normal, toLight);

        // Clamp intensity
        intensity = Math.max(0.2f, Math.min(1, intensity + ambientLight.intensity));

        // Apply to material color
        int r = (int) (materialColor.getRed() * intensity);
        int g = (int) (materialColor.getGreen() * intensity);
        int b = (int) (materialColor.getBlue() * intensity);

        return new java.awt.Color(r, g, b);
    }

    /**
     * Get shaded color based on surface normal
     * Simplified for 2D rendering
     */
    public java.awt.Color getShadedColor(java.awt.Color baseColor, Projection.Vector3f normal) {
        // Simple shading: brighter if normal faces camera
        Projection.Vector3f cameraDir = new Projection.Vector3f(0, 0, 1).normalize();
        float brightness = Math.max(0.3f, normal.dot(cameraDir));

        int r = (int) (baseColor.getRed() * brightness);
        int g = (int) (baseColor.getGreen() * brightness);
        int b = (int) (baseColor.getBlue() * brightness);

        return new java.awt.Color(
            Math.min(255, r),
            Math.min(255, g),
            Math.min(255, b)
        );
    }
}

package com.teamname.furniviz.renderer3d;

import java.awt.Color;

/**
 * LightingManager - Manages lighting in the 3D scene
 *
 * Handles:
 * - Ambient lighting
 * - Directional lights
 * - Light color and intensity
 */
public class LightingManager {

    /**
     * Light - Represents a light source
     */
    public static class Light {
        public Projection.Vector3f position;     // Position in world space
        public Projection.Vector3f direction;    // Direction for directional lights
        public Color color;
        public float intensity;
        public LightType type;

        public enum LightType {
            AMBIENT,        // Uniform light everywhere
            DIRECTIONAL,    // Light from infinite distance (sun)
            POINT,          // Light from a point (bulb)
            SPOT            // Directional light from a point
        }

        public Light(LightType type, Color color, float intensity) {
            this.type = type;
            this.color = color;
            this.intensity = intensity;
            this.position = new Projection.Vector3f(0, 0, 0);
            this.direction = new Projection.Vector3f(0, -1, 0);  // Default: down
        }
    }

    private Light ambientLight;
    private Light directionalLight;

    /**
     * Default constructor - sets up standard lighting
     */
    public LightingManager() {
        // Ambient light: soft white light everywhere
        ambientLight = new Light(
            Light.LightType.AMBIENT,
            Color.WHITE,
            0.5f  // 50% ambient
        );

        // Directional light: sun-like light from top-left
        directionalLight = new Light(
            Light.LightType.DIRECTIONAL,
            Color.WHITE,
            0.8f  // 80% intensity
        );
        directionalLight.direction = new Projection.Vector3f(-1, -1, -1).normalize();
    }

    // ============================================================================
    // GETTERS/SETTERS
    // ============================================================================

    public Light getAmbientLight() { return ambientLight; }
    public Light getDirectionalLight() { return directionalLight; }

    public void setAmbientLight(Color color, float intensity) {
        ambientLight.color = color;
        ambientLight.intensity = Math.max(0, Math.min(1, intensity));
    }

    public void setDirectionalLight(Projection.Vector3f direction, Color color, float intensity) {
        directionalLight.direction = direction.normalize();
        directionalLight.color = color;
        directionalLight.intensity = Math.max(0, Math.min(1, intensity));
    }

    // ============================================================================
    // LIGHTING CALCULATIONS
    // ============================================================================

    /**
     * Calculate lighting intensity at a point given a normal
     * Uses simple Phong-like lighting model
     */
    public float calculateLightIntensity(Projection.Vector3f normal, Projection.Vector3f toLight) {
        // Ensure normal and light direction are normalized
        Projection.Vector3f n = normal.normalize();
        Projection.Vector3f l = toLight.normalize();

        // Lambert's cosine law
        float diffuse = Math.max(0, n.dot(l));

        return diffuse;
    }

    /**
     * Calculate final color given material color and lighting
     */
    public java.awt.Color calculateFinalColor(java.awt.Color materialColor,
                                              Projection.Vector3f normal,
                                              Projection.Vector3f toLight) {
        // Calculate diffuse lighting
        float intensity = calculateLightIntensity(normal, toLight);

        // Clamp intensity
        intensity = Math.max(0.2f, Math.min(1, intensity + ambientLight.intensity));

        // Apply to material color
        int r = (int) (materialColor.getRed() * intensity);
        int g = (int) (materialColor.getGreen() * intensity);
        int b = (int) (materialColor.getBlue() * intensity);

        return new java.awt.Color(r, g, b);
    }

    /**
     * Get shaded color based on surface normal
     * Simplified for 2D rendering
     */
    public java.awt.Color getShadedColor(java.awt.Color baseColor, Projection.Vector3f normal) {
        // Simple shading: brighter if normal faces camera
        Projection.Vector3f cameraDir = new Projection.Vector3f(0, 0, 1).normalize();
        float brightness = Math.max(0.3f, normal.dot(cameraDir));

        int r = (int) (baseColor.getRed() * brightness);
        int g = (int) (baseColor.getGreen() * brightness);
        int b = (int) (baseColor.getBlue() * brightness);

        return new java.awt.Color(
            Math.min(255, r),
            Math.min(255, g),
            Math.min(255, b)
        );
    }

    /**
     * Get enhanced shaded color with multiple lights
     * Combines ambient and directional lighting
     */
    public java.awt.Color getEnhancedShadedColor(java.awt.Color baseColor, Projection.Vector3f normal) {
        if (normal == null || baseColor == null) {
            return baseColor;
        }

        // Normalize the normal
        Projection.Vector3f n = normal.normalize();

        // Ambient contribution
        float ambientR = ambientLight.intensity * ambientLight.color.getRed() / 255f;
        float ambientG = ambientLight.intensity * ambientLight.color.getGreen() / 255f;
        float ambientB = ambientLight.intensity * ambientLight.color.getBlue() / 255f;

        // Directional light contribution
        float diffuse = Math.max(0, n.dot(directionalLight.direction));
        float dirR = directionalLight.intensity * diffuse * directionalLight.color.getRed() / 255f;
        float dirG = directionalLight.intensity * diffuse * directionalLight.color.getGreen() / 255f;
        float dirB = directionalLight.intensity * diffuse * directionalLight.color.getBlue() / 255f;

        // Total lighting
        float totalR = Math.min(1, ambientR + dirR);
        float totalG = Math.min(1, ambientG + dirG);
        float totalB = Math.min(1, ambientB + dirB);

        // Apply to material color
        int r = (int) (baseColor.getRed() * totalR);
        int g = (int) (baseColor.getGreen() * totalG);
        int b = (int) (baseColor.getBlue() * totalB);

        return new java.awt.Color(
            Math.max(0, Math.min(255, r)),
            Math.max(0, Math.min(255, g)),
            Math.max(0, Math.min(255, b))
        );
    }

    /**
     * Get edge-highlighted color (for wireframe/outline rendering)
     * Makes edges more visible
     */
    public java.awt.Color getEdgeHighlightColor(java.awt.Color baseColor) {
        // Darken edges for better visibility
        return new java.awt.Color(
            (int) (baseColor.getRed() * 0.5),
            (int) (baseColor.getGreen() * 0.5),
            (int) (baseColor.getBlue() * 0.5)
        );
    }

    /**
     * Rotate directional light (for dynamic lighting effects)
     */
    public void rotateLightDirection(float angleX, float angleY) {
        Projection.Vector3f dir = directionalLight.direction;
        
        // Simple rotation approximation (would be matrix rotation in production)
        float x = dir.x;
        float y = dir.y;
        float z = dir.z;

        // Rotate around Y axis
        float newX = (float) (x * Math.cos(angleY) - z * Math.sin(angleY));
        float newZ = (float) (x * Math.sin(angleY) + z * Math.cos(angleY));

        // Rotate around X axis
        float newY = (float) (y * Math.cos(angleX) + newZ * Math.sin(angleX));
        newZ = (float) (-y * Math.sin(angleX) + newZ * Math.cos(angleX));

        directionalLight.direction = new Projection.Vector3f(newX, newY, newZ).normalize();
    }
}

package com.teamname.furniviz.renderer3d;

import java.awt.Color;

/**
 * Material - Defines how a surface looks and interacts with light
 *
 * Properties:
 * - Diffuse: Base color (responds to diffuse lighting)
 * - Specular: Highlight color (for shiny surfaces)
 * - Ambient: Color in shadow (prevents complete darkness)
 * - Shininess: How reflective/smooth the surface is (1-128)
 *
 * Higher shininess = more mirror-like
 * Lower shininess = more matte
 */
public class Material {
    public Color diffuse;      // Base color
    public Color specular;     // Highlight color (usually white or bright)
    public Color ambient;      // Shadow color (usually dark version of diffuse)
    public float shininess;    // Surface smoothness (1-128)

    /**
     * Create a material with all properties
     */
    public Material(Color diffuse, Color specular, Color ambient, float shininess) {
        this.diffuse = diffuse;
        this.specular = specular;
        this.ambient = ambient;
        this.shininess = Math.max(1, Math.min(128, shininess));  // Clamp to 1-128
    }

    /**
     * Create a basic matte material
     * Specular and ambient are automatically derived from diffuse
     */
    public Material(Color diffuse) {
        this.diffuse = diffuse;
        this.shininess = 32;  // Medium shine

        // Specular: bright white for highlights
        this.specular = Color.WHITE;

        // Ambient: darker version of diffuse
        int r = Math.max(20, (int) (diffuse.getRed() * 0.3f));
        int g = Math.max(20, (int) (diffuse.getGreen() * 0.3f));
        int b = Math.max(20, (int) (diffuse.getBlue() * 0.3f));
        this.ambient = new Color(r, g, b);
    }

    /**
     * Create a shiny material (like polished wood or metal)
     */
    public static Material createShiny(Color diffuse) {
        int r = Math.max(50, (int) (diffuse.getRed() * 0.5f));
        int g = Math.max(50, (int) (diffuse.getGreen() * 0.5f));
        int b = Math.max(50, (int) (diffuse.getBlue() * 0.5f));
        Color ambient = new Color(r, g, b);
        return new Material(diffuse, Color.WHITE, ambient, 96);  // Very shiny
    }

    /**
     * Create a matte material (like fabric or paper)
     */
    public static Material createMatte(Color diffuse) {
        Color ambient = new Color(
            Math.max(10, (int) (diffuse.getRed() * 0.2f)),
            Math.max(10, (int) (diffuse.getGreen() * 0.2f)),
            Math.max(10, (int) (diffuse.getBlue() * 0.2f))
        );
        return new Material(diffuse, new Color(100, 100, 100), ambient, 16);  // Low shine
    }

    /**
     * Create a metal material
     */
    public static Material createMetal(Color diffuse) {
        Color specular = new Color(
            Math.min(255, diffuse.getRed() + 80),
            Math.min(255, diffuse.getGreen() + 80),
            Math.min(255, diffuse.getBlue() + 80)
        );
        Color ambient = new Color(
            Math.max(30, (int) (diffuse.getRed() * 0.4f)),
            Math.max(30, (int) (diffuse.getGreen() * 0.4f)),
            Math.max(30, (int) (diffuse.getBlue() * 0.4f))
        );
        return new Material(diffuse, specular, ambient, 112);  // Very reflective
    }

    /**
     * Get material for a furniture type
     */
    public static Material getMaterialForFurniture(String furnitureType, Color baseColor) {
        String type = furnitureType.toUpperCase();

        switch (type) {
            case "SOFA":
            case "CHAIR":
            case "OFFICE_CHAIR":
                return Material.createMatte(baseColor);  // Fabric

            case "DESK":
            case "TABLE":
            case "DINING_TABLE":
            case "COFFEE_TABLE":
                return Material.createShiny(baseColor);  // Polished wood

            case "BED":
                return Material.createMatte(baseColor);  // Fabric/mattress

            case "LAMP":
                return Material.createShiny(baseColor);  // Smooth finish

            case "CABINET":
            case "BOOKSHELF":
                return Material.createShiny(baseColor);  // Polished wood/material

            default:
                return new Material(baseColor);  // Basic material
        }
    }

    /**
     * Apply lighting to this material
     * Uses Phong lighting model with specular highlights
     */
    public Color applyPhongLighting(
            Projection.Vector3f normal,
            Projection.Vector3f toLight,
            Projection.Vector3f toCamera,
            float ambientIntensity,
            float diffuseIntensity,
            float specularIntensity) {

        if (normal == null || toLight == null || toCamera == null) {
            return diffuse;
        }

        normal = normal.normalize();
        toLight = toLight.normalize();
        toCamera = toCamera.normalize();

        // Ambient component
        float ambient = ambientIntensity;

        // Diffuse component (Lambert's cosine law)
        float diffuse = Math.max(0, normal.dot(toLight)) * diffuseIntensity;

        // Specular component (Phong model)
        Projection.Vector3f reflect = reflect(toLight, normal);
        float specular = 0;
        if (diffuse > 0) {  // Only calculate specular if diffuse > 0
            float spec = Math.max(0, reflect.dot(toCamera));
            specular = (float) Math.pow(spec, this.shininess / 32.0f) * specularIntensity;
        }

        // Combine components
        float r = ambient * this.ambient.getRed() +
                  diffuse * this.diffuse.getRed() +
                  specular * this.specular.getRed();
        float g = ambient * this.ambient.getGreen() +
                  diffuse * this.diffuse.getGreen() +
                  specular * this.specular.getGreen();
        float b = ambient * this.ambient.getBlue() +
                  diffuse * this.diffuse.getBlue() +
                  specular * this.specular.getBlue();

        // Clamp values to 0-255
        int r255 = Math.min(255, (int) r);
        int g255 = Math.min(255, (int) g);
        int b255 = Math.min(255, (int) b);

        return new Color(r255, g255, b255);
    }

    /**
     * Calculate reflection vector
     * Given light direction and surface normal, calculate reflected direction
     */
    private Projection.Vector3f reflect(Projection.Vector3f v, Projection.Vector3f n) {
        float dot = v.dot(n);
        return v.subtract(n.multiply(2 * dot));
    }

    @Override
    public String toString() {
        return String.format("Material(diffuse=%s, shininess=%.0f)", diffuse, shininess);
    }
}

package com.teamname.furniviz.renderer3d;

import java.awt.Color;
import java.util.ArrayList;
import java.util.List;

/**
 * MeshFactory - Creates 3D mesh geometry from furniture data
 *
 * A mesh is:
 * - Vertices: 3D points that define corners
 * - Faces: triangles connecting vertices
 * - Normals: directions perpendicular to faces (for lighting)
 * - Color: RGB color to fill with
 */
public class MeshFactory {

    /**
     * Mesh - Data structure for 3D geometry
     *
     * Contains all info needed to render a 3D object:
     * - vertices: List of 3D points
     * - indices: Which vertices form triangles (faces)
     * - normals: Direction perpendicular to each face (for lighting)
     * - color: Color to fill with
     * - position: Where to place in world (optional, for convenience)
     * - rotation: Rotation in radians (optional, for convenience)
     */
    public static class Mesh {
        public List<Projection.Vector3f> vertices = new ArrayList<>();
        public List<Integer> indices = new ArrayList<>();
        public List<Projection.Vector3f> normals = new ArrayList<>();
        public Color color;
        public Projection.Vector3f position = new Projection.Vector3f(0, 0, 0);
        public float rotation = 0;

        public Mesh(Color color) {
            this.color = color;
        }

        /**
         * Add a vertex (point) to the mesh
         * Returns the index of this vertex for use in faces
         */
        public int addVertex(Projection.Vector3f v) {
            int index = vertices.size();
            vertices.add(v);
            return index;
        }

        /**
         * Add a triangular face using vertex indices
         * Example: face(0, 1, 2) creates triangle from vertices 0, 1, 2
         */
        public void addFace(int v1, int v2, int v3) {
            indices.add(v1);
            indices.add(v2);
            indices.add(v3);
        }

        /**
         * Calculate normals for all faces
         * Normals are used for lighting (determines brightness of surface)
         */
        public void calculateNormals() {
            // Initialize empty normals for all vertices
            while (normals.size() < vertices.size()) {
                normals.add(new Projection.Vector3f(0, 0, 0));
            }

            // For each face, calculate its normal
            for (int i = 0; i < indices.size(); i += 3) {
                Projection.Vector3f v1 = vertices.get(indices.get(i));
                Projection.Vector3f v2 = vertices.get(indices.get(i + 1));
                Projection.Vector3f v3 = vertices.get(indices.get(i + 2));

                // Calculate edge vectors
                Projection.Vector3f edge1 = v2.subtract(v1);
                Projection.Vector3f edge2 = v3.subtract(v1);

                // Normal is perpendicular to both edges
                Projection.Vector3f faceNormal = edge1.cross(edge2).normalize();

                // Add this normal to all three vertices of the face
                normals.set(indices.get(i), normals.get(indices.get(i)).add(faceNormal));
                normals.set(indices.get(i + 1), normals.get(indices.get(i + 1)).add(faceNormal));
                normals.set(indices.get(i + 2), normals.get(indices.get(i + 2)).add(faceNormal));
            }

            // Normalize all vertex normals
            for (int i = 0; i < normals.size(); i++) {
                normals.set(i, normals.get(i).normalize());
            }
        }

        @Override
        public String toString() {
            return String.format("Mesh(%d vertices, %d faces, color=%s)",
                    vertices.size(), indices.size() / 3, color);
        }
    }

    // ============================================================================
    // MESH GENERATORS
    // ============================================================================

    /**
     * Create a box (cuboid) mesh
     *
     * Used for: furniture (desks, tables, beds, etc.)
     *
     * @param width X dimension
     * @param height Y dimension (vertical)
     * @param depth Z dimension
     * @param color Mesh color
     * @return Mesh representing the box
     */
    public static Mesh createBox(double width, double height, double depth, Color color) {
        Mesh mesh = new Mesh(color);

        // Convert to float and divide by 2 (center around origin)
        float w = (float) width / 2;
        float h = (float) height / 2;
        float d = (float) depth / 2;

        // Create 8 vertices for corners of the box
        // Front face
        int v0 = mesh.addVertex(new Projection.Vector3f(-w, -h, d));  // Front-bottom-left
        int v1 = mesh.addVertex(new Projection.Vector3f(w, -h, d));   // Front-bottom-right
        int v2 = mesh.addVertex(new Projection.Vector3f(w, h, d));    // Front-top-right
        int v3 = mesh.addVertex(new Projection.Vector3f(-w, h, d));   // Front-top-left

        // Back face
        int v4 = mesh.addVertex(new Projection.Vector3f(-w, -h, -d)); // Back-bottom-left
        int v5 = mesh.addVertex(new Projection.Vector3f(w, -h, -d));  // Back-bottom-right
        int v6 = mesh.addVertex(new Projection.Vector3f(w, h, -d));   // Back-top-right
        int v7 = mesh.addVertex(new Projection.Vector3f(-w, h, -d));  // Back-top-left

        // Create 6 faces (2 triangles per face)
        // Front face
        mesh.addFace(v0, v2, v1);
        mesh.addFace(v0, v3, v2);

        // Back face
        mesh.addFace(v5, v7, v6);
        mesh.addFace(v5, v4, v7);

        // Top face
        mesh.addFace(v3, v6, v7);
        mesh.addFace(v3, v2, v6);

        // Bottom face
        mesh.addFace(v4, v1, v5);
        mesh.addFace(v4, v0, v1);

        // Left face
        mesh.addFace(v4, v3, v7);
        mesh.addFace(v4, v0, v3);

        // Right face
        mesh.addFace(v1, v6, v5);
        mesh.addFace(v1, v2, v6);

        // Calculate lighting normals
        mesh.calculateNormals();

        return mesh;
    }

    /**
     * Create a plane (flat rectangle)
     *
     * Used for: room floor, walls, ceilings
     */
    public static Mesh createPlane(double width, double height, Color color) {
        Mesh mesh = new Mesh(color);

        float w = (float) width / 2;
        float h = (float) height / 2;

        int v0 = mesh.addVertex(new Projection.Vector3f(-w, 0, -h));
        int v1 = mesh.addVertex(new Projection.Vector3f(w, 0, -h));
        int v2 = mesh.addVertex(new Projection.Vector3f(w, 0, h));
        int v3 = mesh.addVertex(new Projection.Vector3f(-w, 0, h));

        mesh.addFace(v0, v2, v1);
        mesh.addFace(v0, v3, v2);

        mesh.calculateNormals();

        return mesh;
    }

    /**
     * Create a cylinder (for round furniture)
     *
     * Used for: round tables, chairs, stools, lamps
     * (Implemented in Phase 2)
     */
    public static Mesh createCylinder(double radius, double height, int segments, Color color) {
        // TODO: Implement in Phase 2
        throw new UnsupportedOperationException("Cylinder generation not yet implemented");
    }
}

package com.teamname.furniviz.renderer3d;

import java.awt.Color;
import java.util.ArrayList;
import java.util.List;

/**
 * MeshFactory - Creates 3D mesh geometry from furniture data
 *
 * A mesh is:
 * - Vertices: 3D points that define corners
 * - Faces: triangles connecting vertices
 * - Normals: directions perpendicular to faces (for lighting)
 * - Color: RGB color to fill with
 */
public class MeshFactory {

    /**
     * Mesh - Data structure for 3D geometry
     *
     * Contains all info needed to render a 3D object:
     * - vertices: List of 3D points
     * - indices: Which vertices form triangles (faces)
     * - normals: Direction perpendicular to each face (for lighting)
     * - color: Color to fill with
     * - position: Where to place in world (optional, for convenience)
     * - rotation: Rotation in radians (optional, for convenience)
     */
    public static class Mesh {
        public List<Projection.Vector3f> vertices = new ArrayList<>();
        public List<Integer> indices = new ArrayList<>();
        public List<Projection.Vector3f> normals = new ArrayList<>();
        public Color color;
        public Projection.Vector3f position = new Projection.Vector3f(0, 0, 0);
        public float rotation = 0;

        public Mesh(Color color) {
            this.color = color;
        }

        /**
         * Add a vertex (point) to the mesh
         * Returns the index of this vertex for use in faces
         */
        public int addVertex(Projection.Vector3f v) {
            int index = vertices.size();
            vertices.add(v);
            return index;
        }

        /**
         * Add a triangular face using vertex indices
         * Example: face(0, 1, 2) creates triangle from vertices 0, 1, 2
         */
        public void addFace(int v1, int v2, int v3) {
            indices.add(v1);
            indices.add(v2);
            indices.add(v3);
        }

        /**
         * Calculate normals for all faces
         * Normals are used for lighting (determines brightness of surface)
         */
        public void calculateNormals() {
            // Initialize empty normals for all vertices
            while (normals.size() < vertices.size()) {
                normals.add(new Projection.Vector3f(0, 0, 0));
            }

            // For each face, calculate its normal
            for (int i = 0; i < indices.size(); i += 3) {
                Projection.Vector3f v1 = vertices.get(indices.get(i));
                Projection.Vector3f v2 = vertices.get(indices.get(i + 1));
                Projection.Vector3f v3 = vertices.get(indices.get(i + 2));

                // Calculate edge vectors
                Projection.Vector3f edge1 = v2.subtract(v1);
                Projection.Vector3f edge2 = v3.subtract(v1);

                // Normal is perpendicular to both edges
                Projection.Vector3f faceNormal = edge1.cross(edge2).normalize();

                // Add this normal to all three vertices of the face
                normals.set(indices.get(i), normals.get(indices.get(i)).add(faceNormal));
                normals.set(indices.get(i + 1), normals.get(indices.get(i + 1)).add(faceNormal));
                normals.set(indices.get(i + 2), normals.get(indices.get(i + 2)).add(faceNormal));
            }

            // Normalize all vertex normals
            for (int i = 0; i < normals.size(); i++) {
                normals.set(i, normals.get(i).normalize());
            }
        }

        @Override
        public String toString() {
            return String.format("Mesh(%d vertices, %d faces, color=%s)",
                    vertices.size(), indices.size() / 3, color);
        }
    }

    // ============================================================================
    // MESH GENERATORS
    // ============================================================================

    /**
     * Create a box (cuboid) mesh
     *
     * Used for: furniture (desks, tables, beds, etc.)
     *
     * @param width X dimension
     * @param height Y dimension (vertical)
     * @param depth Z dimension
     * @param color Mesh color
     * @return Mesh representing the box
     */
    public static Mesh createBox(double width, double height, double depth, Color color) {
        Mesh mesh = new Mesh(color);

        // Convert to float and divide by 2 (center around origin)
        float w = (float) width / 2;
        float h = (float) height / 2;
        float d = (float) depth / 2;

        // Create 8 vertices for corners of the box
        // Front face
        int v0 = mesh.addVertex(new Projection.Vector3f(-w, -h, d));  // Front-bottom-left
        int v1 = mesh.addVertex(new Projection.Vector3f(w, -h, d));   // Front-bottom-right
        int v2 = mesh.addVertex(new Projection.Vector3f(w, h, d));    // Front-top-right
        int v3 = mesh.addVertex(new Projection.Vector3f(-w, h, d));   // Front-top-left

        // Back face
        int v4 = mesh.addVertex(new Projection.Vector3f(-w, -h, -d)); // Back-bottom-left
        int v5 = mesh.addVertex(new Projection.Vector3f(w, -h, -d));  // Back-bottom-right
        int v6 = mesh.addVertex(new Projection.Vector3f(w, h, -d));   // Back-top-right
        int v7 = mesh.addVertex(new Projection.Vector3f(-w, h, -d));  // Back-top-left

        // Create 6 faces (2 triangles per face)
        // Front face
        mesh.addFace(v0, v2, v1);
        mesh.addFace(v0, v3, v2);

        // Back face
        mesh.addFace(v5, v7, v6);
        mesh.addFace(v5, v4, v7);

        // Top face
        mesh.addFace(v3, v6, v7);
        mesh.addFace(v3, v2, v6);

        // Bottom face
        mesh.addFace(v4, v1, v5);
        mesh.addFace(v4, v0, v1);

        // Left face
        mesh.addFace(v4, v3, v7);
        mesh.addFace(v4, v0, v3);

        // Right face
        mesh.addFace(v1, v6, v5);
        mesh.addFace(v1, v2, v6);

        // Calculate lighting normals
        mesh.calculateNormals();

        return mesh;
    }

    /**
     * Create a plane (flat rectangle)
     *
     * Used for: room floor, walls, ceilings
     */
    public static Mesh createPlane(double width, double height, Color color) {
        Mesh mesh = new Mesh(color);

        float w = (float) width / 2;
        float h = (float) height / 2;

        int v0 = mesh.addVertex(new Projection.Vector3f(-w, 0, -h));
        int v1 = mesh.addVertex(new Projection.Vector3f(w, 0, -h));
        int v2 = mesh.addVertex(new Projection.Vector3f(w, 0, h));
        int v3 = mesh.addVertex(new Projection.Vector3f(-w, 0, h));

        mesh.addFace(v0, v2, v1);
        mesh.addFace(v0, v3, v2);

        mesh.calculateNormals();

        return mesh;
    }

    /**
     * Create a cylinder (for round furniture)
     *
     * Used for: round tables, chairs, stools, lamps
     */
    public static Mesh createCylinder(double radius, double height, int segments, Color color) {
        Mesh mesh = new Mesh(color);
        
        float r = (float) radius;
        float h = (float) height / 2;
        
        // Create top and bottom center vertices
        int topCenter = mesh.addVertex(new Projection.Vector3f(0, h, 0));
        int bottomCenter = mesh.addVertex(new Projection.Vector3f(0, -h, 0));
        
        // Create vertices around cylinder
        int[] topVertices = new int[segments];
        int[] bottomVertices = new int[segments];
        
        for (int i = 0; i < segments; i++) {
            float angle = (float) (2 * Math.PI * i / segments);
            float x = r * (float) Math.cos(angle);
            float z = r * (float) Math.sin(angle);
            
            topVertices[i] = mesh.addVertex(new Projection.Vector3f(x, h, z));
            bottomVertices[i] = mesh.addVertex(new Projection.Vector3f(x, -h, z));
        }
        
        // Create faces
        for (int i = 0; i < segments; i++) {
            int next = (i + 1) % segments;
            
            // Top cap
            mesh.addFace(topCenter, topVertices[next], topVertices[i]);
            
            // Bottom cap
            mesh.addFace(bottomCenter, bottomVertices[i], bottomVertices[next]);
            
            // Side faces
            mesh.addFace(topVertices[i], bottomVertices[i], topVertices[next]);
            mesh.addFace(topVertices[next], bottomVertices[i], bottomVertices[next]);
        }
        
        mesh.calculateNormals();
        return mesh;
    }
    
    /**
     * Create furniture-specific mesh based on type
     * 
     * Different furniture types get different shapes for more realistic visualization
     */
    public static Mesh createFurnitureByType(String furnitureType, double width, double height, 
                                            double depth, Color color) {
        // Convert type to uppercase for comparison
        String type = furnitureType.toUpperCase();
        
        switch (type) {
            case "SOFA":
                return createSofaMesh(width, height, depth, color);
            case "CHAIR":
                return createChairMesh(width, height, depth, color);
            case "TABLE":
            case "DINING_TABLE":
            case "COFFEE_TABLE":
                return createTableMesh(width, height, depth, color);
            case "BED":
                return createBedMesh(width, height, depth, color);
            case "DESK":
                return createDeskMesh(width, height, depth, color);
            case "LAMP":
                return createLampMesh(width, height, depth, color);
            case "CABINET":
            case "BOOKSHELF":
                return createCabinetMesh(width, height, depth, color);
            default:
                // Fallback to simple box
                return createBox(width, height, depth, color);
        }
    }
    
    /**
     * Create a sofa mesh (cushioned seating with back)
     */
    private static Mesh createSofaMesh(double width, double height, double depth, Color color) {
        Mesh mesh = new Mesh(color);
        
        float w = (float) width / 2;
        float h = (float) height / 2;
        float d = (float) depth / 2;
        
        // Base (main seating surface)
        int base_v0 = mesh.addVertex(new Projection.Vector3f(-w, -h, d));
        int base_v1 = mesh.addVertex(new Projection.Vector3f(w, -h, d));
        int base_v2 = mesh.addVertex(new Projection.Vector3f(w, -h * 0.5f, d));
        int base_v3 = mesh.addVertex(new Projection.Vector3f(-w, -h * 0.5f, d));
        
        int base_v4 = mesh.addVertex(new Projection.Vector3f(-w, -h, -d));
        int base_v5 = mesh.addVertex(new Projection.Vector3f(w, -h, -d));
        int base_v6 = mesh.addVertex(new Projection.Vector3f(w, -h * 0.5f, -d));
        int base_v7 = mesh.addVertex(new Projection.Vector3f(-w, -h * 0.5f, -d));
        
        // Add base faces
        mesh.addFace(base_v0, base_v2, base_v1);
        mesh.addFace(base_v0, base_v3, base_v2);
        mesh.addFace(base_v5, base_v7, base_v6);
        mesh.addFace(base_v5, base_v4, base_v7);
        
        // Back cushion (simplified as box in back)
        int back_v0 = mesh.addVertex(new Projection.Vector3f(-w, -h * 0.3f, -d));
        int back_v1 = mesh.addVertex(new Projection.Vector3f(w, -h * 0.3f, -d));
        int back_v2 = mesh.addVertex(new Projection.Vector3f(w, h * 0.7f, -d));
        int back_v3 = mesh.addVertex(new Projection.Vector3f(-w, h * 0.7f, -d));
        
        mesh.addFace(back_v0, back_v2, back_v1);
        mesh.addFace(back_v0, back_v3, back_v2);
        
        mesh.calculateNormals();
        return mesh;
    }
    
    /**
     * Create a chair mesh (seat + back)
     */
    private static Mesh createChairMesh(double width, double height, double depth, Color color) {
        Mesh mesh = new Mesh(color);
        
        float w = (float) width / 3;  // Chair is narrower
        float h = (float) height / 2;
        float d = (float) depth / 2;
        
        // Seat
        int seat_v0 = mesh.addVertex(new Projection.Vector3f(-w, -h, d));
        int seat_v1 = mesh.addVertex(new Projection.Vector3f(w, -h, d));
        int seat_v2 = mesh.addVertex(new Projection.Vector3f(w, 0, d));
        int seat_v3 = mesh.addVertex(new Projection.Vector3f(-w, 0, d));
        
        int seat_v4 = mesh.addVertex(new Projection.Vector3f(-w, -h, -d));
        int seat_v5 = mesh.addVertex(new Projection.Vector3f(w, -h, -d));
        int seat_v6 = mesh.addVertex(new Projection.Vector3f(w, 0, -d));
        int seat_v7 = mesh.addVertex(new Projection.Vector3f(-w, 0, -d));
        
        // Add seat faces
        mesh.addFace(seat_v0, seat_v2, seat_v1);
        mesh.addFace(seat_v0, seat_v3, seat_v2);
        
        // Back rest (thin vertical)
        int back_v0 = mesh.addVertex(new Projection.Vector3f(-w * 0.9f, 0, -d * 0.8f));
        int back_v1 = mesh.addVertex(new Projection.Vector3f(w * 0.9f, 0, -d * 0.8f));
        int back_v2 = mesh.addVertex(new Projection.Vector3f(w * 0.9f, h * 0.8f, -d * 0.8f));
        int back_v3 = mesh.addVertex(new Projection.Vector3f(-w * 0.9f, h * 0.8f, -d * 0.8f));
        
        mesh.addFace(back_v0, back_v2, back_v1);
        mesh.addFace(back_v0, back_v3, back_v2);
        
        mesh.calculateNormals();
        return mesh;
    }
    
    /**
     * Create a table mesh (surface with legs)
     */
    private static Mesh createTableMesh(double width, double height, double depth, Color color) {
        Mesh mesh = new Mesh(color);
        
        float w = (float) width / 2;
        float h = (float) height / 2;
        float d = (float) depth / 2;
        float legThickness = Math.min(w, d) * 0.2f;
        
        // Table top
        int top_v0 = mesh.addVertex(new Projection.Vector3f(-w, h, -d));
        int top_v1 = mesh.addVertex(new Projection.Vector3f(w, h, -d));
        int top_v2 = mesh.addVertex(new Projection.Vector3f(w, h, d));
        int top_v3 = mesh.addVertex(new Projection.Vector3f(-w, h, d));
        
        mesh.addFace(top_v0, top_v2, top_v1);
        mesh.addFace(top_v0, top_v3, top_v2);
        
        // Legs (4 small boxes at corners)
        float legX = w * 0.7f;
        float legZ = d * 0.7f;
        
        // Front-left leg
        int leg1_v0 = mesh.addVertex(new Projection.Vector3f(-legX, -h, -legZ));
        int leg1_v1 = mesh.addVertex(new Projection.Vector3f(-legX + legThickness, -h, -legZ));
        int leg1_v2 = mesh.addVertex(new Projection.Vector3f(-legX + legThickness, h, -legZ));
        int leg1_v3 = mesh.addVertex(new Projection.Vector3f(-legX, h, -legZ));
        
        mesh.addFace(leg1_v0, leg1_v2, leg1_v1);
        mesh.addFace(leg1_v0, leg1_v3, leg1_v2);
        
        // Additional legs (similar pattern for other 3 corners)
        // For simplicity, just add the main leg - in production would add all 4
        
        mesh.calculateNormals();
        return mesh;
    }
    
    /**
     * Create a bed mesh (frame + mattress)
     */
    private static Mesh createBedMesh(double width, double height, double depth, Color color) {
        // Bed is relatively flat - create a box slightly modified
        Mesh mesh = new Mesh(color);
        
        float w = (float) width / 2;
        float h = (float) height / 4;  // Bed is low profile
        float d = (float) depth / 2;
        
        // Simple box for bed (mattress + frame)
        int v0 = mesh.addVertex(new Projection.Vector3f(-w, -h, d));
        int v1 = mesh.addVertex(new Projection.Vector3f(w, -h, d));
        int v2 = mesh.addVertex(new Projection.Vector3f(w, h, d));
        int v3 = mesh.addVertex(new Projection.Vector3f(-w, h, d));
        
        int v4 = mesh.addVertex(new Projection.Vector3f(-w, -h, -d));
        int v5 = mesh.addVertex(new Projection.Vector3f(w, -h, -d));
        int v6 = mesh.addVertex(new Projection.Vector3f(w, h, -d));
        int v7 = mesh.addVertex(new Projection.Vector3f(-w, h, -d));
        
        mesh.addFace(v0, v2, v1);
        mesh.addFace(v0, v3, v2);
        mesh.addFace(v5, v7, v6);
        mesh.addFace(v5, v4, v7);
        
        mesh.calculateNormals();
        return mesh;
    }
    
    /**
     * Create a desk mesh (flat surface, like table but lower)
     */
    private static Mesh createDeskMesh(double width, double height, double depth, Color color) {
        // Desk is similar to table, just with different proportions
        return createTableMesh(width * 1.2, height * 0.6, depth * 0.8, color);
    }
    
    /**
     * Create a lamp mesh (stand + bulb area)
     */
    private static Mesh createLampMesh(double width, double height, double depth, Color color) {
        // Use cylinder for lamp (stand)
        return createCylinder(Math.min(width, depth) * 0.3, height, 16, color);
    }
    
    /**
     * Create a cabinet/bookshelf mesh (tall storage)
     */
    private static Mesh createCabinetMesh(double width, double height, double depth, Color color) {
        // Cabinet is just a box, similar to standard furniture
        return createBox(width, height, depth, color);
    }
}

package com.teamname.furniviz.renderer3d;

import com.teamname.furniviz.furniture.FurnitureItem;
import java.awt.Color;
import java.util.HashMap;
import java.util.Map;

/**
 * RenderCache - Caches generated meshes to avoid redundant computation
 *
 * Benefits:
 * - Reduced CPU overhead when scene doesn't change
 * - Faster frame rendering
 * - Scalable to many furniture items
 *
 * The cache automatically invalidates entries when furniture properties change
 */
public class RenderCache {

    /**
     * Cache entry metadata
     */
    private static class CacheEntry {
        MeshFactory.Mesh mesh;
        long lastUsed;

        CacheEntry(MeshFactory.Mesh mesh) {
            this.mesh = mesh;
            this.lastUsed = System.currentTimeMillis();
        }
    }

    // Cache storage: key = furniture hash, value = cached mesh
    private Map<String, CacheEntry> meshCache = new HashMap<>();

    // Cache statistics
    private int cacheHits = 0;
    private int cacheMisses = 0;
    private int totalCacheSize = 0;
    private static final int MAX_CACHE_SIZE = 500;  // Maximum entries

    /**
     * Generate cache key for a furniture item
     * Key includes all properties that affect mesh generation
     */
    private String generateCacheKey(String furnitureType, double width, double height, 
                                   double depth, Color color) {
        return String.format("%s_%.2f_%.2f_%.2f_%d_%d_%d",
            furnitureType.toUpperCase(),
            width, height, depth,
            color.getRed(), color.getGreen(), color.getBlue());
    }

    /**
     * Generate cache key from FurnitureItem
     */
    private String generateCacheKey(FurnitureItem item) {
        return generateCacheKey(
            item.getType().toString(),
            item.getWidth(),
            item.getHeight(),
            item.getDepth(),
            item.getColor()
        );
    }

    /**
     * Get or create furniture mesh with caching
     * 
     * @param item The furniture item
     * @return Cached or newly created mesh
     */
    public MeshFactory.Mesh getFurnitureMesh(FurnitureItem item) {
        String key = generateCacheKey(item);

        // Check if in cache
        if (meshCache.containsKey(key)) {
            CacheEntry entry = meshCache.get(key);
            entry.lastUsed = System.currentTimeMillis();
            cacheHits++;
            return entry.mesh;
        }

        // Not in cache, create new mesh
        cacheMisses++;
        MeshFactory.Mesh mesh = MeshFactory.createFurnitureByType(
            item.getType().toString(),
            item.getWidth(),
            item.getHeight(),
            item.getDepth(),
            item.getColor()
        );

        // Add to cache
        addToCache(key, mesh);
        return mesh;
    }

    /**
     * Get or create box mesh with caching
     */
    public MeshFactory.Mesh getBoxMesh(double width, double height, double depth, Color color) {
        String key = generateCacheKey("BOX", width, height, depth, color);

        if (meshCache.containsKey(key)) {
            CacheEntry entry = meshCache.get(key);
            entry.lastUsed = System.currentTimeMillis();
            cacheHits++;
            return entry.mesh;
        }

        cacheMisses++;
        MeshFactory.Mesh mesh = MeshFactory.createBox(width, height, depth, color);
        addToCache(key, mesh);
        return mesh;
    }

    /**
     * Get or create plane mesh with caching
     */
    public MeshFactory.Mesh getPlaneMesh(double width, double depth, Color color) {
        String key = String.format("PLANE_%.2f_%.2f_%d_%d_%d",
            width, depth, color.getRed(), color.getGreen(), color.getBlue());

        if (meshCache.containsKey(key)) {
            CacheEntry entry = meshCache.get(key);
            entry.lastUsed = System.currentTimeMillis();
            cacheHits++;
            return entry.mesh;
        }

        cacheMisses++;
        MeshFactory.Mesh mesh = MeshFactory.createPlane(width, depth, color);
        addToCache(key, mesh);
        return mesh;
    }

    /**
     * Add mesh to cache, with eviction if necessary
     */
    private void addToCache(String key, MeshFactory.Mesh mesh) {
        // Evict least recently used entry if cache is full
        if (totalCacheSize >= MAX_CACHE_SIZE) {
            evictLRUEntry();
        }

        meshCache.put(key, new CacheEntry(mesh));
        totalCacheSize++;
    }

    /**
     * Evict least recently used entry
     */
    private void evictLRUEntry() {
        String lruKey = null;
        long oldestTime = Long.MAX_VALUE;

        for (String key : meshCache.keySet()) {
            long time = meshCache.get(key).lastUsed;
            if (time < oldestTime) {
                oldestTime = time;
                lruKey = key;
            }
        }

        if (lruKey != null) {
            meshCache.remove(lruKey);
            totalCacheSize--;
        }
    }

    /**
     * Clear entire cache
     */
    public void clear() {
        meshCache.clear();
        totalCacheSize = 0;
        cacheHits = 0;
        cacheMisses = 0;
    }

    /**
     * Get cache hit rate as percentage
     */
    public float getCacheHitRate() {
        int total = cacheHits + cacheMisses;
        if (total == 0) return 0;
        return (float) cacheHits / total * 100;
    }

    /**
     * Get cache statistics string for debugging
     */
    public String getStatistics() {
        int total = cacheHits + cacheMisses;
        float hitRate = total > 0 ? (float) cacheHits / total * 100 : 0;
        return String.format("Cache: %d/%d hits (%.1f%%) | Size: %d/%d",
            cacheHits, total, hitRate, totalCacheSize, MAX_CACHE_SIZE);
    }

    public int getCacheSize() { return totalCacheSize; }
    public int getCacheHits() { return cacheHits; }
    public int getCacheMisses() { return cacheMisses; }
}

package com.teamname.furniviz.renderer3d;

import com.teamname.furniviz.app.DesignState;
import com.teamname.furniviz.furniture.FurnitureItem;
import com.teamname.furniviz.room.Room;

import java.awt.Color;
import java.awt.Font;
import java.awt.Graphics2D;
import java.awt.Point;
import java.awt.RenderingHints;
import java.util.List;

/**
 * Renderer3D - Main 3D scene manager and rendering engine
 *
 * Responsibilities:
 * - Manage 3D scene graph
 * - Create and update room and furniture geometry
 * - Handle lighting and materials
 * - Maintain camera and rendering state
 * - Provide interface for rendering to canvas
 */
public class Renderer3D {

    // Reference to shared design state
    private DesignState designState;

    // Scene components
    private Camera camera;
    private SceneGraph sceneGraph;
    private LightingManager lighting;

    // Render state
    private boolean showGrid = true;
    private boolean showNormals = false;
    private RenderMode renderMode = RenderMode.SOLID;

    // Performance tracking
    private long lastUpdateTime = 0;
    private int frameCount = 0;
    private float fps = 0;

    /**
     * Render mode - how to render the scene
     */
    public enum RenderMode {
        WIREFRAME,      // Show triangle edges only
        SOLID,          // Show filled triangles
        SHADED          // Show with lighting
    }

    /**
     * Constructor
     * @param designState The shared application state
     */
    public Renderer3D(DesignState designState) {
        this.designState = designState;
        this.camera = new Camera();
        this.sceneGraph = new SceneGraph();
        this.lighting = new LightingManager();

        // Initialize scene with room and furniture
        rebuildScene();
    }

    // ============================================================================
    // SCENE MANAGEMENT
    // ============================================================================

    /**
     * Rebuild entire scene from DesignState
     * Called when room or major properties change
     */
    public void rebuildScene() {
        sceneGraph.clear();

        // Get current room
        Room room = designState.getRoom();
        if (room == null) {
            return;  // No room to render
        }

        // Create room geometry
        createRoomGeometry(room);

        // Create furniture geometry
        List<FurnitureItem> items = designState.getFurnitureItems();
        for (FurnitureItem item : items) {
            createFurnitureGeometry(item);
        }
    }

    /**
     * Update scene based on DesignState changes
     * More efficient than rebuilding entire scene
     */
    public void update() {
        // Check for furniture changes
        List<FurnitureItem> items = designState.getFurnitureItems();

        // Update existing furniture nodes
        for (int i = 0; i < items.size(); i++) {
            FurnitureItem item = items.get(i);
            SceneNode furnitureNode = sceneGraph.getFurnitureNode(i);

            if (furnitureNode != null) {
                // Update position and rotation
                furnitureNode.setPosition(
                    (float) item.getX(),
                    (float) item.getHeight() / 2,
                    (float) item.getY()
                );
                furnitureNode.setRotation(
                    0,  // X rotation
                    Projection.convertRotation(item.getRotation()),  // Y rotation
                    0   // Z rotation
                );
            }
        }

        // Track FPS
        updateFPS();
    }

    /**
     * Create 3D geometry for room (floor, walls, ceiling)
     */
    private void createRoomGeometry(Room room) {
        double width = room.getWidth();
        double length = room.getLength();
        Color wallColor = room.getWallColor();

        // Floor (XZ plane at y=0)
        MeshFactory.Mesh floorMesh = MeshFactory.createPlane(width, length, Color.LIGHT_GRAY);
        SceneNode floorNode = new SceneNode("Floor");
        floorNode.setMesh(floorMesh);
        floorNode.setPosition(0, 0, 0);
        sceneGraph.addNode(floorNode);

        // Walls - use boxes for simplicity
        float wallHeight = 3.0f;  // Standard wall height
        float wallThickness = 0.1f;

        // Front wall (Z = length/2)
        createWall("FrontWall", (float)width, wallHeight, wallThickness,
                   0, wallHeight/2, (float)length/2, wallColor);

        // Back wall (Z = -length/2)
        createWall("BackWall", (float)width, wallHeight, wallThickness,
                   0, wallHeight/2, (float)-length/2, wallColor);

        // Left wall (X = -width/2)
        createWall("LeftWall", wallThickness, wallHeight, (float)length,
                   (float)-width/2, wallHeight/2, 0, wallColor);

        // Right wall (X = width/2)
        createWall("RightWall", wallThickness, wallHeight, (float)length,
                   (float)width/2, wallHeight/2, 0, wallColor);

        // Ceiling (optional)
        MeshFactory.Mesh ceilingMesh = MeshFactory.createPlane(width, length, Color.WHITE);
        SceneNode ceilingNode = new SceneNode("Ceiling");
        ceilingNode.setMesh(ceilingMesh);
        ceilingNode.setPosition(0, wallHeight, 0);
        sceneGraph.addNode(ceilingNode);
    }

    /**
     * Helper method to create a wall
     */
    private void createWall(String name, float width, float height, float depth,
                           float x, float y, float z, Color color) {
        MeshFactory.Mesh wallMesh = MeshFactory.createBox(width, height, depth, color);
        SceneNode wallNode = new SceneNode(name);
        wallNode.setMesh(wallMesh);
        wallNode.setPosition(x, y, z);
        sceneGraph.addNode(wallNode);
    }

    /**
     * Create 3D geometry for furniture item
     */
    private void createFurnitureGeometry(FurnitureItem item) {
        // Create box geometry based on furniture dimensions
        MeshFactory.Mesh furnitureMesh = MeshFactory.createBox(
            item.getWidth(),
            item.getHeight(),
            item.getDepth(),
            item.getColor()
        );

        // Create scene node
        SceneNode furnitureNode = new SceneNode(item.getName());
        furnitureNode.setMesh(furnitureMesh);

        // Set position (x, y in 2D → x, z in 3D, offset by height/2)
        furnitureNode.setPosition(
            (float) item.getX(),
            (float) item.getHeight() / 2,
            (float) item.getY()
        );

        // Set rotation (2D rotation → Y-axis rotation in 3D)
        furnitureNode.setRotation(
            0,  // X rotation (pitch)
            Projection.convertRotation(item.getRotation()),  // Y rotation (yaw)
            0   // Z rotation (roll)
        );

        sceneGraph.addFurnitureNode(furnitureNode);
    }

    // ============================================================================
    // RENDERING INTERFACE
    // ============================================================================

    /**
     * Render the 3D scene to a Graphics2D context
     * This is called by Canvas3D for Swing rendering
     */
    public void render(Graphics2D g, int width, int height) {
        if (g == null) return;

        // Clear background
        g.setColor(new Color(50, 50, 50));
        g.fillRect(0, 0, width, height);

        // If no room, display message
        if (designState.getRoom() == null) {
            g.setColor(Color.WHITE);
            g.setFont(new Font("Arial", Font.BOLD, 14));
            g.drawString("Load a room to view in 3D", width / 2 - 100, height / 2);
            return;
        }

        // Set anti-aliasing for better quality
        g.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);

        // Render room geometry
        renderRoomGeometry(g, width, height);

        // Render furniture geometry
        renderFurnitureGeometry(g, width, height);

        // Draw statistics
        drawStatistics(g, width, height);
    }

    /**
     * Render room (floor, walls, ceiling)
     */
    private void renderRoomGeometry(Graphics2D g, int width, int height) {
        Room room = designState.getRoom();
        if (room == null) return;

        float roomWidth = (float) room.getWidth();
        float roomLength = (float) room.getLength();
        float wallHeight = 2.5f;

        // Draw floor
        Projection.Vector3f[] floorCorners = new Projection.Vector3f[]{
            new Projection.Vector3f(0, 0, 0),
            new Projection.Vector3f(roomWidth, 0, 0),
            new Projection.Vector3f(roomWidth, 0, roomLength),
            new Projection.Vector3f(0, 0, roomLength)
        };

        Point[] floorScreenCoords = DrawingUtils.projectPoints(floorCorners, camera, width, height);
        if (floorScreenCoords != null && floorScreenCoords.length >= 3) {
            Color floorColor = new Color(180, 180, 180);  // Light gray
            DrawingUtils.drawFilledPolygon(g, floorScreenCoords, floorColor, Color.BLACK);
        }

        // Draw front wall (Z = 0)
        Projection.Vector3f[] frontWallCorners = new Projection.Vector3f[]{
            new Projection.Vector3f(0, 0, 0),
            new Projection.Vector3f(roomWidth, 0, 0),
            new Projection.Vector3f(roomWidth, wallHeight, 0),
            new Projection.Vector3f(0, wallHeight, 0)
        };

        Point[] frontWallScreenCoords = DrawingUtils.projectPoints(frontWallCorners, camera, width, height);
        if (frontWallScreenCoords != null && frontWallScreenCoords.length >= 3) {
            Color wallColor = room.getWallColor() != null ? room.getWallColor() : new Color(220, 220, 220);
            DrawingUtils.drawFilledPolygon(g, frontWallScreenCoords, wallColor, Color.BLACK);
        }

        // Draw left wall (X = 0)
        Projection.Vector3f[] leftWallCorners = new Projection.Vector3f[]{
            new Projection.Vector3f(0, 0, 0),
            new Projection.Vector3f(0, 0, roomLength),
            new Projection.Vector3f(0, wallHeight, roomLength),
            new Projection.Vector3f(0, wallHeight, 0)
        };

        Point[] leftWallScreenCoords = DrawingUtils.projectPoints(leftWallCorners, camera, width, height);
        if (leftWallScreenCoords != null && leftWallScreenCoords.length >= 3) {
            Color wallColor = room.getWallColor() != null ? room.getWallColor() : new Color(200, 200, 200);
            DrawingUtils.drawFilledPolygon(g, leftWallScreenCoords, wallColor, Color.BLACK);
        }
    }

    /**
     * Render all furniture as 3D boxes
     */
    private void renderFurnitureGeometry(Graphics2D g, int width, int height) {
        for (FurnitureItem item : designState.getFurnitureItems()) {
            renderFurnitureItem(g, item, width, height);
        }
    }

    /**
     * Render a single furniture item as a 3D box
     */
    private void renderFurnitureItem(Graphics2D g, FurnitureItem item, int width, int height) {
        float itemX = (float) item.getX();
        float itemY = (float) item.getY();
        float itemW = (float) item.getWidth();
        float itemH = (float) item.getHeight();
        float itemD = (float) item.getDepth();
        float itemRotation = (float) item.getRotation();

        // Create box vertices
        Projection.Vector3f[] boxVertices = DrawingUtils.createBoxVertices(
            itemX + itemW / 2,
            itemH / 2,
            itemY + itemD / 2,
            itemW, itemH, itemD
        );

        // Project vertices to 2D
        Point[] screenVertices = DrawingUtils.projectPoints(boxVertices, camera, width, height);
        if (screenVertices == null || screenVertices.length < 8) {
            return;  // Can't render
        }

        // Get box faces
        int[][] faces = DrawingUtils.getBoxFaces();

        // Draw each visible face
        Color itemColor = item.getColor() != null ? item.getColor() : Color.BLUE;

        for (int faceIdx = 0; faceIdx < faces.length; faceIdx++) {
            int[] faceIndices = faces[faceIdx];

            // Get face vertices
            Point[] faceScreenCoords = new Point[faceIndices.length];
            for (int i = 0; i < faceIndices.length; i++) {
                faceScreenCoords[i] = screenVertices[faceIndices[i]];
            }

            // Apply simple lighting based on face normal
            Projection.Vector3f[] faceWorldCoords = new Projection.Vector3f[faceIndices.length];
            for (int i = 0; i < faceIndices.length; i++) {
                faceWorldCoords[i] = boxVertices[faceIndices[i]];
            }

            Projection.Vector3f faceNormal = DrawingUtils.calculateNormal(
                faceWorldCoords[0], faceWorldCoords[1], faceWorldCoords[2]);

            // Light direction (from above and behind)
            Projection.Vector3f lightDirection = new Projection.Vector3f(1, 1, -1).normalize();

            float lighting = DrawingUtils.calculateLighting(faceNormal, lightDirection, 0.3f);
            Color shadedColor = DrawingUtils.applyLighting(itemColor, lighting);

            // Draw face
            DrawingUtils.drawFilledPolygon(g, faceScreenCoords, shadedColor, Color.BLACK);
        }
    }

    /**
     * Draw debug statistics on screen
     */
    private void drawStatistics(Graphics2D g, int width, int height) {
        g.setColor(Color.WHITE);
        g.setFont(new Font("Arial", Font.PLAIN, 11));
        g.setRenderingHint(RenderingHints.KEY_TEXT_ANTIALIASING, RenderingHints.VALUE_TEXT_ANTIALIAS_ON);

        int y = 20;
        int lineHeight = 18; // Increased for better spacing

        Room room = designState.getRoom();
        if (room != null) {
            g.drawString("Room: " + room.getWidth() + "m x " + room.getLength() + "m", 10, y);
            y += lineHeight;
        }

        g.drawString("Furniture: " + designState.getFurnitureItems().size(), 10, y);
        y += lineHeight;

        g.drawString("Camera: " + camera.getPosition().toString(), 10, y);
    }

    /**
     * Get the scene graph
     */
    public SceneGraph getSceneGraph() {
        return sceneGraph;
    }

    // ============================================================================
    // SCENE NODES AND MATRICES
    // ============================================================================
    public List<SceneNode> getSceneNodes() {
        return sceneGraph.getAllNodes();
    }

    /**
     * Get a specific scene node by name
     */
    public SceneNode getSceneNode(String name) {
        return sceneGraph.getNode(name);
    }

    /**
     * Get transform matrices for rendering
     */
    public Projection.Matrix4f getWorldMatrix(SceneNode node) {
        return node.getWorldMatrix();
    }

    public Projection.Matrix4f getViewMatrix() {
        return camera.getViewMatrix();
    }

    public Projection.Matrix4f getProjectionMatrix(float aspectRatio) {
        return camera.getPerspectiveMatrix(aspectRatio);
    }

    // ============================================================================
    // CAMERA CONTROLS
    // ============================================================================

    public Camera getCamera() { return camera; }

    public void setCamera(Camera cam) { this.camera = cam; }

    public void orbitCamera(float deltaY, float deltaX) {
        camera.orbit(deltaY, deltaX);
    }

    public void panCamera(float deltaX, float deltaZ) {
        camera.pan(deltaX, deltaZ);
    }

    public void zoomCamera(float delta) {
        if (delta > 0) {
            camera.zoomIn();
        } else {
            camera.zoomOut();
        }
    }

    // ============================================================================
    // RENDERING STATE
    // ============================================================================

    public RenderMode getRenderMode() { return renderMode; }
    public void setRenderMode(RenderMode mode) { this.renderMode = mode; }

    public boolean isGridShown() { return showGrid; }
    public void setShowGrid(boolean show) { this.showGrid = show; }

    public boolean areNormalsShown() { return showNormals; }
    public void setShowNormals(boolean show) { this.showNormals = show; }

    // ============================================================================
    // LIGHTING
    // ============================================================================

    public LightingManager getLighting() { return lighting; }

    // ============================================================================
    // PERFORMANCE TRACKING
    // ============================================================================

    private void updateFPS() {
        long currentTime = System.currentTimeMillis();
        frameCount++;

        if (currentTime - lastUpdateTime >= 1000) {  // Every second
            fps = frameCount;
            frameCount = 0;
            lastUpdateTime = currentTime;
        }
    }

    public float getFPS() { return fps; }

    @Override
    public String toString() {
        return String.format("Renderer3D[camera=%s, nodes=%d, fps=%.1f]",
            camera, sceneGraph.nodeCount(), fps);
    }
}

package com.teamname.furniviz.renderer3d;

import com.teamname.furniviz.app.DesignState;
import com.teamname.furniviz.furniture.FurnitureItem;
import com.teamname.furniviz.room.Room;

import java.awt.Color;
import java.awt.Font;
import java.awt.Graphics2D;
import java.awt.Point;
import java.awt.RenderingHints;
import java.util.List;

/**
 * Renderer3D - Main 3D scene manager and rendering engine
 *
 * Responsibilities:
 * - Manage 3D scene graph
 * - Create and update room and furniture geometry
 * - Handle lighting and materials
 * - Maintain camera and rendering state
 * - Provide interface for rendering to canvas
 */
public class Renderer3D {

    // Reference to shared design state
    private DesignState designState;

    // Scene components
    private Camera camera;
    private SceneGraph sceneGraph;
    private LightingManager lighting;
    private RenderCache renderCache;  // NEW: Mesh caching system

    // Render state
    private boolean showGrid = true;
    private boolean showNormals = false;
    private RenderMode renderMode = RenderMode.SOLID;

    // Performance tracking
    private long lastUpdateTime = 0;
    private int frameCount = 0;
    private float fps = 0;

    /**
     * Render mode - how to render the scene
     */
    public enum RenderMode {
        WIREFRAME,      // Show triangle edges only
        SOLID,          // Show filled triangles
        SHADED          // Show with lighting
    }

    /**
     * Constructor
     * @param designState The shared application state
     */
    public Renderer3D(DesignState designState) {
        this.designState = designState;
        this.camera = new Camera();
        this.sceneGraph = new SceneGraph();
        this.lighting = new LightingManager();
        this.renderCache = new RenderCache();  // NEW: Initialize cache

        // Initialize scene with room and furniture
        rebuildScene();
    }

    // ============================================================================
    // SCENE MANAGEMENT
    // ============================================================================

    /**
     * Rebuild entire scene from DesignState
     * Called when room or major properties change
     */
    public void rebuildScene() {
        sceneGraph.clear();

        // Get current room
        Room room = designState.getRoom();
        if (room == null) {
            return;  // No room to render
        }

        // Create room geometry
        createRoomGeometry(room);

        // Create furniture geometry
        List<FurnitureItem> items = designState.getFurnitureItems();
        for (FurnitureItem item : items) {
            createFurnitureGeometry(item);
        }
    }

    /**
     * Update scene based on DesignState changes
     * More efficient than rebuilding entire scene
     */
    public void update() {
        // Check for furniture changes
        List<FurnitureItem> items = designState.getFurnitureItems();

        // Update existing furniture nodes
        for (int i = 0; i < items.size(); i++) {
            FurnitureItem item = items.get(i);
            SceneNode furnitureNode = sceneGraph.getFurnitureNode(i);

            if (furnitureNode != null) {
                // Update position and rotation
                furnitureNode.setPosition(
                    (float) item.getX(),
                    (float) item.getHeight() / 2,
                    (float) item.getY()
                );
                furnitureNode.setRotation(
                    0,  // X rotation
                    Projection.convertRotation(item.getRotation()),  // Y rotation
                    0   // Z rotation
                );
            }
        }

        // Track FPS
        updateFPS();
    }

    /**
     * Create 3D geometry for room (floor, walls, ceiling)
     */
    private void createRoomGeometry(Room room) {
        double width = room.getWidth();
        double length = room.getLength();
        Color wallColor = room.getWallColor();

        // Floor (XZ plane at y=0)
        MeshFactory.Mesh floorMesh = MeshFactory.createPlane(width, length, Color.LIGHT_GRAY);
        SceneNode floorNode = new SceneNode("Floor");
        floorNode.setMesh(floorMesh);
        floorNode.setPosition(0, 0, 0);
        sceneGraph.addNode(floorNode);

        // Walls - use boxes for simplicity
        float wallHeight = 3.0f;  // Standard wall height
        float wallThickness = 0.1f;

        // Front wall (Z = length/2)
        createWall("FrontWall", (float)width, wallHeight, wallThickness,
                   0, wallHeight/2, (float)length/2, wallColor);

        // Back wall (Z = -length/2)
        createWall("BackWall", (float)width, wallHeight, wallThickness,
                   0, wallHeight/2, (float)-length/2, wallColor);

        // Left wall (X = -width/2)
        createWall("LeftWall", wallThickness, wallHeight, (float)length,
                   (float)-width/2, wallHeight/2, 0, wallColor);

        // Right wall (X = width/2)
        createWall("RightWall", wallThickness, wallHeight, (float)length,
                   (float)width/2, wallHeight/2, 0, wallColor);

        // Ceiling (optional)
        MeshFactory.Mesh ceilingMesh = MeshFactory.createPlane(width, length, Color.WHITE);
        SceneNode ceilingNode = new SceneNode("Ceiling");
        ceilingNode.setMesh(ceilingMesh);
        ceilingNode.setPosition(0, wallHeight, 0);
        sceneGraph.addNode(ceilingNode);
    }

    /**
     * Helper method to create a wall
     */
    private void createWall(String name, float width, float height, float depth,
                           float x, float y, float z, Color color) {
        MeshFactory.Mesh wallMesh = MeshFactory.createBox(width, height, depth, color);
        SceneNode wallNode = new SceneNode(name);
        wallNode.setMesh(wallMesh);
        wallNode.setPosition(x, y, z);
        sceneGraph.addNode(wallNode);
    }

    /**
     * Create 3D geometry for furniture item
     * Now uses furniture-type-specific meshes for better visualization
     */
    private void createFurnitureGeometry(FurnitureItem item) {
        // Create furniture-specific geometry based on type
        // This provides much better visual representation than generic boxes
        MeshFactory.Mesh furnitureMesh = MeshFactory.createFurnitureByType(
            item.getType().toString(),
            item.getWidth(),
            item.getHeight(),
            item.getDepth(),
            item.getColor()
        );

        // Create scene node
        SceneNode furnitureNode = new SceneNode(item.getName());
        furnitureNode.setMesh(furnitureMesh);

        // Set position (x, y in 2D → x, z in 3D, offset by height/2)
        furnitureNode.setPosition(
            (float) item.getX(),
            (float) item.getHeight() / 2,
            (float) item.getY()
        );

        // Set rotation (2D rotation → Y-axis rotation in 3D)
        furnitureNode.setRotation(
            0,  // X rotation (pitch)
            Projection.convertRotation(item.getRotation()),  // Y rotation (yaw)
            0   // Z rotation (roll)
        );

        sceneGraph.addFurnitureNode(furnitureNode);
    }

    // ============================================================================
    // RENDERING INTERFACE
    // ============================================================================

    /**
     * Render the 3D scene to a Graphics2D context
     * This is called by Canvas3D for Swing rendering
     */
    public void render(Graphics2D g, int width, int height) {
        if (g == null) return;

        // Clear background
        g.setColor(new Color(50, 50, 50));
        g.fillRect(0, 0, width, height);

        // If no room, display message
        if (designState.getRoom() == null) {
            g.setColor(Color.WHITE);
            g.setFont(new Font("Arial", Font.BOLD, 14));
            g.drawString("Load a room to view in 3D", width / 2 - 100, height / 2);
            return;
        }

        // Set anti-aliasing for better quality
        g.setRenderingHint(RenderingHints.KEY_ANTIALIASING, RenderingHints.VALUE_ANTIALIAS_ON);

        // Render room geometry
        renderRoomGeometry(g, width, height);

        // Render furniture geometry
        renderFurnitureGeometry(g, width, height);

        // Draw statistics
        drawStatistics(g, width, height);
    }

    /**
     * Render room (floor, walls, ceiling)
     */
    private void renderRoomGeometry(Graphics2D g, int width, int height) {
        Room room = designState.getRoom();
        if (room == null) return;

        float roomWidth = (float) room.getWidth();
        float roomLength = (float) room.getLength();
        float wallHeight = 2.5f;

        // Draw floor
        Projection.Vector3f[] floorCorners = new Projection.Vector3f[]{
            new Projection.Vector3f(0, 0, 0),
            new Projection.Vector3f(roomWidth, 0, 0),
            new Projection.Vector3f(roomWidth, 0, roomLength),
            new Projection.Vector3f(0, 0, roomLength)
        };

        Point[] floorScreenCoords = DrawingUtils.projectPoints(floorCorners, camera, width, height);
        if (floorScreenCoords != null && floorScreenCoords.length >= 3) {
            Color floorColor = new Color(180, 180, 180);  // Light gray
            DrawingUtils.drawFilledPolygon(g, floorScreenCoords, floorColor, Color.BLACK);
        }

        // Draw front wall (Z = 0)
        Projection.Vector3f[] frontWallCorners = new Projection.Vector3f[]{
            new Projection.Vector3f(0, 0, 0),
            new Projection.Vector3f(roomWidth, 0, 0),
            new Projection.Vector3f(roomWidth, wallHeight, 0),
            new Projection.Vector3f(0, wallHeight, 0)
        };

        Point[] frontWallScreenCoords = DrawingUtils.projectPoints(frontWallCorners, camera, width, height);
        if (frontWallScreenCoords != null && frontWallScreenCoords.length >= 3) {
            Color wallColor = room.getWallColor() != null ? room.getWallColor() : new Color(220, 220, 220);
            DrawingUtils.drawFilledPolygon(g, frontWallScreenCoords, wallColor, Color.BLACK);
        }

        // Draw left wall (X = 0)
        Projection.Vector3f[] leftWallCorners = new Projection.Vector3f[]{
            new Projection.Vector3f(0, 0, 0),
            new Projection.Vector3f(0, 0, roomLength),
            new Projection.Vector3f(0, wallHeight, roomLength),
            new Projection.Vector3f(0, wallHeight, 0)
        };

        Point[] leftWallScreenCoords = DrawingUtils.projectPoints(leftWallCorners, camera, width, height);
        if (leftWallScreenCoords != null && leftWallScreenCoords.length >= 3) {
            Color wallColor = room.getWallColor() != null ? room.getWallColor() : new Color(200, 200, 200);
            DrawingUtils.drawFilledPolygon(g, leftWallScreenCoords, wallColor, Color.BLACK);
        }
    }

    /**
     * Render all furniture as 3D boxes
     */
    private void renderFurnitureGeometry(Graphics2D g, int width, int height) {
        for (FurnitureItem item : designState.getFurnitureItems()) {
            renderFurnitureItem(g, item, width, height);
        }
    }

    /**
     * Render a single furniture item as a 3D box
     */
    private void renderFurnitureItem(Graphics2D g, FurnitureItem item, int width, int height) {
        float itemX = (float) item.getX();
        float itemY = (float) item.getY();
        float itemW = (float) item.getWidth();
        float itemH = (float) item.getHeight();
        float itemD = (float) item.getDepth();
        float itemRotation = (float) item.getRotation();

        // Create box vertices
        Projection.Vector3f[] boxVertices = DrawingUtils.createBoxVertices(
            itemX + itemW / 2,
            itemH / 2,
            itemY + itemD / 2,
            itemW, itemH, itemD
        );

        // Project vertices to 2D
        Point[] screenVertices = DrawingUtils.projectPoints(boxVertices, camera, width, height);
        if (screenVertices == null || screenVertices.length < 8) {
            return;  // Can't render
        }

        // Get box faces
        int[][] faces = DrawingUtils.getBoxFaces();

        // Draw each visible face
        Color itemColor = item.getColor() != null ? item.getColor() : Color.BLUE;

        for (int faceIdx = 0; faceIdx < faces.length; faceIdx++) {
            int[] faceIndices = faces[faceIdx];

            // Get face vertices
            Point[] faceScreenCoords = new Point[faceIndices.length];
            for (int i = 0; i < faceIndices.length; i++) {
                faceScreenCoords[i] = screenVertices[faceIndices[i]];
            }

            // Apply simple lighting based on face normal
            Projection.Vector3f[] faceWorldCoords = new Projection.Vector3f[faceIndices.length];
            for (int i = 0; i < faceIndices.length; i++) {
                faceWorldCoords[i] = boxVertices[faceIndices[i]];
            }

            Projection.Vector3f faceNormal = DrawingUtils.calculateNormal(
                faceWorldCoords[0], faceWorldCoords[1], faceWorldCoords[2]);

            // Light direction (from above and behind)
            Projection.Vector3f lightDirection = new Projection.Vector3f(1, 1, -1).normalize();

            float lighting = DrawingUtils.calculateLighting(faceNormal, lightDirection, 0.3f);
            Color shadedColor = DrawingUtils.applyLighting(itemColor, lighting);

            // Draw face
            DrawingUtils.drawFilledPolygon(g, faceScreenCoords, shadedColor, Color.BLACK);
        }
    }

    /**
     * Draw debug statistics on screen
     */
    private void drawStatistics(Graphics2D g, int width, int height) {
        g.setColor(Color.WHITE);
        g.setFont(new Font("Arial", Font.PLAIN, 11));
        g.setRenderingHint(RenderingHints.KEY_TEXT_ANTIALIASING, RenderingHints.VALUE_TEXT_ANTIALIAS_ON);

        int y = 20;
        int lineHeight = 18; // Increased for better spacing

        Room room = designState.getRoom();
        if (room != null) {
            g.drawString("Room: " + room.getWidth() + "m x " + room.getLength() + "m", 10, y);
            y += lineHeight;
        }

        g.drawString("Furniture: " + designState.getFurnitureItems().size(), 10, y);
        y += lineHeight;

        g.drawString("Camera: " + camera.getPosition().toString(), 10, y);
    }

    /**
     * Get the scene graph
     */
    public SceneGraph getSceneGraph() {
        return sceneGraph;
    }

    // ============================================================================
    // SCENE NODES AND MATRICES
    // ============================================================================
    public List<SceneNode> getSceneNodes() {
        return sceneGraph.getAllNodes();
    }

    /**
     * Get a specific scene node by name
     */
    public SceneNode getSceneNode(String name) {
        return sceneGraph.getNode(name);
    }

    /**
     * Get transform matrices for rendering
     */
    public Projection.Matrix4f getWorldMatrix(SceneNode node) {
        return node.getWorldMatrix();
    }

    public Projection.Matrix4f getViewMatrix() {
        return camera.getViewMatrix();
    }

    public Projection.Matrix4f getProjectionMatrix(float aspectRatio) {
        return camera.getPerspectiveMatrix(aspectRatio);
    }

    // ============================================================================
    // CAMERA CONTROLS
    // ============================================================================

    public Camera getCamera() { return camera; }

    public void setCamera(Camera cam) { this.camera = cam; }

    public void orbitCamera(float deltaY, float deltaX) {
        camera.orbit(deltaY, deltaX);
    }

    public void panCamera(float deltaX, float deltaZ) {
        camera.pan(deltaX, deltaZ);
    }

    public void zoomCamera(float delta) {
        if (delta > 0) {
            camera.zoomIn();
        } else {
            camera.zoomOut();
        }
    }

    // ============================================================================
    // RENDERING STATE
    // ============================================================================

    public RenderMode getRenderMode() { return renderMode; }
    public void setRenderMode(RenderMode mode) { this.renderMode = mode; }

    public boolean isGridShown() { return showGrid; }
    public void setShowGrid(boolean show) { this.showGrid = show; }

    public boolean areNormalsShown() { return showNormals; }
    public void setShowNormals(boolean show) { this.showNormals = show; }

    // ============================================================================
    // LIGHTING
    // ============================================================================

    public LightingManager getLighting() { return lighting; }

    // ============================================================================
    // RENDER CACHE (NEW)
    // ============================================================================

    public RenderCache getRenderCache() { return renderCache; }

    public void clearRenderCache() { renderCache.clear(); }

    public String getCacheStatistics() { return renderCache.getStatistics(); }

    // ============================================================================
    // PERFORMANCE TRACKING
    // ============================================================================

    private void updateFPS() {
        long currentTime = System.currentTimeMillis();
        frameCount++;

        if (currentTime - lastUpdateTime >= 1000) {  // Every second
            fps = frameCount;
            frameCount = 0;
            lastUpdateTime = currentTime;
        }
    }

    public float getFPS() { return fps; }

    @Override
    public String toString() {
        return String.format("Renderer3D[camera=%s, nodes=%d, fps=%.1f]",
            camera, sceneGraph.nodeCount(), fps);
    }
}

package com.teamname.furniviz.renderer3d;

/**
 * RenderingOptimizations - Contains techniques to improve rendering performance
 *
 * Techniques:
 * 1. Frustum Culling - Don't render objects outside camera view
 * 2. Backface Culling - Don't render faces facing away from camera
 * 3. Level of Detail (LOD) - Use simpler meshes for distant objects
 * 4. Draw Call Batching - Combine similar renders into single call
 * 5. Viewport Optimization - Reduced resolution for distant objects
 */
public class RenderingOptimizations {

    /**
     * Calculate screen-space size of object
     * Used for LOD decisions
     */
    public static float calculateScreenSpaceSize(
            Projection.Vector3f objectPosition,
            float objectRadius,
            Projection.Vector3f cameraPosition,
            float fov) {

        // Distance from camera
        float distance = cameraPosition.distance(objectPosition);
        if (distance <= 0) return 0;

        // Convert FOV to radians and calculate screen space size
        float fovRad = (float) Math.toRadians(fov);
        return (objectRadius * 2) / (float) Math.tan(fovRad / 2) / distance;
    }

    /**
     * Get LOD level based on screen space size
     * Higher = more distant = simpler mesh
     */
    public static int getLODLevel(float screenSpaceSize) {
        if (screenSpaceSize > 0.5f) return 0;      // LOD 0: Full detail
        if (screenSpaceSize > 0.2f) return 1;      // LOD 1: Medium detail
        if (screenSpaceSize > 0.05f) return 2;     // LOD 2: Low detail
        return 3;                                  // LOD 3: Very low detail (billboard)
    }

    /**
     * Check if object is in camera frustum
     * Frustum is the pyramid of vision from the camera
     */
    public static boolean isInFrustum(
            Projection.Vector3f objectPosition,
            float objectRadius,
            Projection.Vector3f cameraPos,
            Projection.Vector3f cameraTarget,
            float fov,
            float aspectRatio,
            float nearPlane,
            float farPlane) {

        // Distance from camera
        Projection.Vector3f toObject = objectPosition.subtract(cameraPos);
        float distance = toObject.length();

        // Check near/far planes
        if (distance - objectRadius > farPlane || distance + objectRadius < nearPlane) {
            return false;
        }

        // Check if within FOV cone
        Projection.Vector3f cameraDir = cameraTarget.subtract(cameraPos).normalize();
        float cosHalfFOV = (float) Math.cos(Math.toRadians(fov / 2));
        float dotProduct = toObject.normalize().dot(cameraDir);

        if (dotProduct < cosHalfFOV) {
            return false;  // Outside FOV cone
        }

        return true;
    }

    /**
     * Calculate approximate pixel footprint for prioritization
     */
    public static float calculatePixelFootprint(
            Projection.Vector3f objectCenter,
            float objectSize,
            Projection.Vector3f cameraPos,
            int screenWidth) {

        float distance = objectCenter.distance(cameraPos);
        if (distance <= 0) return Float.MAX_VALUE;

        return (objectSize * screenWidth) / distance;
    }

    /**
     * Estimate vertex count for object
     */
    public static int estimateVertexCount(
            double width, double height, double depth,
            String meshType) {

        switch (meshType.toUpperCase()) {
            case "BOX":
                return 8;  // 8 corners
            case "SPHERE":
                return 162;  // 9x18 segments = 162 vertices
            case "CYLINDER":
                return 34;   // 16 around + 2 centers
            case "TABLE":
            case "DESK":
                return 12;   // Simplified
            case "SOFA":
                return 20;   // Multiple cushions
            case "CHAIR":
                return 14;   // Seat + back
            case "BED":
                return 8;    // Simple box
            default:
                return 8;
        }
    }

    /**
     * Estimate face count for object
     */
    public static int estimateFaceCount(
            double width, double height, double depth,
            String meshType) {

        switch (meshType.toUpperCase()) {
            case "BOX":
                return 12;  // 2 per side × 6 sides
            case "SPHERE":
                return 324; // 9×18×2 triangles
            case "CYLINDER":
                return 64;  // Side + 2 caps
            case "TABLE":
            case "DESK":
                return 24;  // Simplified
            case "SOFA":
                return 40;  // Multiple surfaces
            case "CHAIR":
                return 28;  // Seat + back + legs
            case "BED":
                return 12;  // Simple box
            default:
                return 12;
        }
    }

    /**
     * Get recommended update frequency based on change rate
     * Returns milliseconds between updates
     */
    public static int getUpdateFrequency(float fps, boolean hasChanges) {
        if (hasChanges) {
            return 16;  // Update every frame if changed
        }

        if (fps > 50) {
            return 33;  // Update every other frame if high FPS
        } else if (fps > 30) {
            return 50;  // Update every 3rd frame
        } else {
            return 100; // Update less frequently if low FPS
        }
    }

    /**
     * Check if scene is static (no changes)
     */
    public static boolean isSceneStatic(long timeSinceLastChange) {
        return timeSinceLastChange > 2000;  // No changes for 2 seconds
    }

    /**
     * Get memory usage string for debugging
     */
    public static String getMemoryUsage() {
        Runtime runtime = Runtime.getRuntime();
        long totalMemory = runtime.totalMemory();
        long freeMemory = runtime.freeMemory();
        long usedMemory = totalMemory - freeMemory;
        long maxMemory = runtime.maxMemory();

        return String.format(
            "Memory: %d/%d MB (Max: %d MB)",
            usedMemory / 1024 / 1024,
            totalMemory / 1024 / 1024,
            maxMemory / 1024 / 1024
        );
    }
}

package com.teamname.furniviz.renderer3d;

/**
 * SceneStatistics - Tracks rendering performance and scene metrics
 *
 * Useful for:
 * - Performance profiling
 * - Identifying bottlenecks
 * - Debug information display
 */
public class SceneStatistics {
    private int totalVertices = 0;
    private int totalFaces = 0;
    private int visibleFaces = 0;
    private int renderedFaces = 0;
    private int furnitureCount = 0;
    private long renderTimeMs = 0;
    private float fps = 0;
    private int cachedMeshes = 0;
    private float cacheHitRate = 0;

    // Tracking variables
    private long frameStartTime = 0;
    private int frameCount = 0;
    private long fpsUpdateTime = 0;

    /**
     * Start frame timing
     */
    public void startFrame() {
        frameStartTime = System.currentTimeMillis();
        totalVertices = 0;
        totalFaces = 0;
        visibleFaces = 0;
        renderedFaces = 0;
    }

    /**
     * End frame timing and update FPS
     */
    public void endFrame() {
        renderTimeMs = System.currentTimeMillis() - frameStartTime;
        frameCount++;

        long now = System.currentTimeMillis();
        if (now - fpsUpdateTime >= 1000) {
            fps = frameCount;
            frameCount = 0;
            fpsUpdateTime = now;
        }
    }

    /**
     * Get comprehensive statistics string
     */
    public String getStatisticsString() {
        return String.format(
            "FPS: %.1f | Render: %dms | Verts: %d | Faces: %d/%d | Furniture: %d | Cache: %d (%.1f%%)",
            fps, renderTimeMs, totalVertices, renderedFaces, totalFaces, 
            furnitureCount, cachedMeshes, cacheHitRate
        );
    }

    /**
     * Get detailed statistics for debugging
     */
    public String getDetailedStatistics() {
        return String.format(
            "=== Scene Statistics ===\n" +
            "FPS: %.1f\n" +
            "Frame Time: %dms\n" +
            "Total Vertices: %d\n" +
            "Total Faces: %d\n" +
            "Visible Faces: %d\n" +
            "Rendered Faces: %d (%.1f%%)\n" +
            "Furniture Items: %d\n" +
            "Cached Meshes: %d\n" +
            "Cache Hit Rate: %.1f%%",
            fps, renderTimeMs, totalVertices, totalFaces, visibleFaces,
            renderedFaces, (float)renderedFaces/totalFaces*100,
            furnitureCount, cachedMeshes, cacheHitRate
        );
    }

    // Setters for tracking
    public void setTotalVertices(int count) { this.totalVertices = count; }
    public void setTotalFaces(int count) { this.totalFaces = count; }
    public void setVisibleFaces(int count) { this.visibleFaces = count; }
    public void setRenderedFaces(int count) { this.renderedFaces = count; }
    public void setFurnitureCount(int count) { this.furnitureCount = count; }
    public void setCachedMeshes(int count) { this.cachedMeshes = count; }
    public void setCacheHitRate(float rate) { this.cacheHitRate = rate; }

    // Getters
    public int getTotalVertices() { return totalVertices; }
    public int getTotalFaces() { return totalFaces; }
    public int getVisibleFaces() { return visibleFaces; }
    public int getRenderedFaces() { return renderedFaces; }
    public int getFurnitureCount() { return furnitureCount; }
    public long getRenderTimeMs() { return renderTimeMs; }
    public float getFPS() { return fps; }
    public int getCachedMeshes() { return cachedMeshes; }
    public float getCacheHitRate() { return cacheHitRate; }
}

package com.teamname.furniviz.storage;

import com.google.gson.Gson;
import com.google.gson.GsonBuilder;
import com.google.gson.JsonObject;
import com.google.gson.JsonArray;
import com.mongodb.client.MongoCollection;
import com.mongodb.client.model.Filters;
import com.mongodb.client.model.IndexOptions;
import com.teamname.furniviz.furniture.FurnitureItem;
import com.teamname.furniviz.furniture.FurnitureType;
import com.teamname.furniviz.room.Room;
import com.teamname.furniviz.room.RoomShape;
import org.bson.Document;
import org.bson.conversions.Bson;

import java.time.Instant;
import java.time.LocalDateTime;
import java.time.ZoneId;
import java.util.*;
import java.util.stream.Collectors;

/**
 * Design Repository - MongoDB-backed CRUD operations for user designs
 * 
 * Replaces in-memory HashMap with permanent MongoDB storage
 * Manages persistence of designs with:
 * - Save/Load/Update/Delete operations
 * - Multi-user filtering (by userId)
 * - Search and filtering capabilities
 * - Full serialization/deserialization support
 */
public class DesignRepository {

    private static final String COLLECTION_NAME = "designs";
    private MongoCollection<Document> designsCollection;
    private static final Gson gson = new GsonBuilder().setPrettyPrinting().create();

    public DesignRepository() {
        MongoDBConnection connection = MongoDBConnection.getInstance();
        this.designsCollection = connection.getCollection(COLLECTION_NAME);
        ensureCollectionsExist();
    }

    /**
     * Ensure designs collection exists with proper indexes
     */
    public void ensureCollectionsExist() {
        try {
            // Create unique index on designId field
            designsCollection.createIndex(
                    new Document("designId", 1),
                    new IndexOptions().unique(true)
            );
            System.out.println("[OK] Designs collection ready with unique designId index");

            // Create index on userId for faster queries
            try {
                designsCollection.createIndex(new Document("userId", 1));
                System.out.println("[OK] Designs collection indexed on userId");
            } catch (Exception e) {
                // Index might already exist
            }
        } catch (Exception e) {
            System.out.println("[INFO] Designs collection/indexes already exist");
        }
    }

    // ========== CREATE OPERATION ==========

    /**
     * Save a new design to MongoDB
     * 
     * @param design The design to save
     * @return true if saved successfully, false otherwise
     */
    public boolean saveDesign(DesignModel design) {
        try {
            if (design == null || design.getDesignId() == null) {
                System.err.println("[ERROR] Cannot save null design or design without ID");
                return false;
            }

            Document designDoc = designToDocument(design);
            designsCollection.insertOne(designDoc);
            System.out.println("[OK] Design saved to MongoDB: " + design.getDesignId() + 
                             " (User: " + design.getUserId() + ", Name: " + design.getDesignName() + ")");
            return true;
        } catch (com.mongodb.MongoWriteException e) {
            if (e.getError().getCategory().toString().contains("DUPLICATE")) {
                System.err.println("[ERROR] Design already exists: " + design.getDesignId());
            } else {
                System.err.println("[ERROR] Error saving design: " + e.getMessage());
            }
            return false;
        } catch (Exception e) {
            System.err.println("[ERROR] Error saving design: " + e.getMessage());
            e.printStackTrace();
            return false;
        }
    }

    // ========== READ OPERATIONS ==========

    /**
     * Get all designs for a specific user from MongoDB
     * 
     * @param userId The owner's user ID
     * @return List of designs belonging to the user
     */
    public List<DesignModel> getDesignsByUserId(String userId) {
        try {
            Bson filter = Filters.eq("userId", userId);
            List<DesignModel> userDesigns = new ArrayList<>();

            for (Document doc : designsCollection.find(filter)) {
                DesignModel design = documentToDesign(doc);
                if (design != null) {
                    userDesigns.add(design);
                }
            }

            System.out.println("[OK] Retrieved " + userDesigns.size() + 
                             " designs for user: " + userId);
            return userDesigns;
        } catch (Exception e) {
            System.err.println("[ERROR] Error retrieving designs: " + e.getMessage());
            e.printStackTrace();
            return new ArrayList<>();
        }
    }

    /**
     * Get a specific design by ID from MongoDB
     * 
     * @param designId The design ID
     * @return The design, or null if not found
     */
    public DesignModel getDesignById(String designId) {
        try {
            Bson filter = Filters.eq("designId", designId);
            Document doc = designsCollection.find(filter).first();

            if (doc == null) {
                System.out.println("[WARNING] Design not found: " + designId);
                return null;
            }

            DesignModel design = documentToDesign(doc);
            System.out.println("[OK] Retrieved design: " + designId);
            return design;
        } catch (Exception e) {
            System.err.println("[ERROR] Error retrieving design: " + e.getMessage());
            return null;
        }
    }

    /**
     * Get all designs (admin only - use with caution!)
     * 
     * @return List of all designs
     */
    public List<DesignModel> getAllDesigns() {
        try {
            List<DesignModel> allDesigns = new ArrayList<>();

            for (Document doc : designsCollection.find()) {
                DesignModel design = documentToDesign(doc);
                if (design != null) {
                    allDesigns.add(design);
                }
            }

            System.out.println("[OK] Retrieved all " + allDesigns.size() + " designs");
            return allDesigns;
        } catch (Exception e) {
            System.err.println("[ERROR] Error retrieving all designs: " + e.getMessage());
            return new ArrayList<>();
        }
    }

    /**
     * Search designs by name for a specific user
     * 
     * @param userId The owner's user ID
     * @param searchTerm The search term (case-insensitive)
     * @return List of matching designs
     */
    public List<DesignModel> searchByName(String userId, String searchTerm) {
        try {
            Bson filter = Filters.and(
                    Filters.eq("userId", userId),
                    Filters.regex("designName", searchTerm, "i")  // Case-insensitive regex
            );

            List<DesignModel> results = new ArrayList<>();
            for (Document doc : designsCollection.find(filter)) {
                DesignModel design = documentToDesign(doc);
                if (design != null) {
                    results.add(design);
                }
            }

            System.out.println("[OK] Found " + results.size() + " designs matching: " + searchTerm);
            return results;
        } catch (Exception e) {
            System.err.println("[ERROR] Error searching designs: " + e.getMessage());
            return new ArrayList<>();
        }
    }

    /**
     * Filter designs by tags
     * 
     * @param userId The owner's user ID
     * @param tag The tag to filter by
     * @return List of designs with the tag
     */
    public List<DesignModel> filterByTag(String userId, String tag) {
        try {
            Bson filter = Filters.and(
                    Filters.eq("userId", userId),
                    Filters.regex("tags", tag, "i")  // Case-insensitive regex
            );

            List<DesignModel> results = new ArrayList<>();
            for (Document doc : designsCollection.find(filter)) {
                DesignModel design = documentToDesign(doc);
                if (design != null) {
                    results.add(design);
                }
            }

            return results;
        } catch (Exception e) {
            System.err.println("[ERROR] Error filtering by tag: " + e.getMessage());
            return new ArrayList<>();
        }
    }

    // ========== UPDATE OPERATION ==========

    /**
     * Update an existing design in MongoDB
     * 
     * @param design The updated design
     * @return true if updated successfully, false otherwise
     */
    public boolean updateDesign(DesignModel design) {
        try {
            if (!designExists(design.getDesignId())) {
                System.err.println("[ERROR] Design not found: " + design.getDesignId());
                return false;
            }

            Bson filter = Filters.eq("designId", design.getDesignId());
            Document designDoc = designToDocument(design);
            designsCollection.replaceOne(filter, designDoc);

            System.out.println("[OK] Design updated in MongoDB: " + design.getDesignId() + 
                             " (Name: " + design.getDesignName() + ")");
            return true;
        } catch (Exception e) {
            System.err.println("[ERROR] Error updating design: " + e.getMessage());
            e.printStackTrace();
            return false;
        }
    }

    // ========== DELETE OPERATION ==========

    /**
     * Delete a design from MongoDB by ID
     * 
     * @param designId The design ID to delete
     * @return true if deleted successfully, false otherwise
     */
    public boolean deleteDesign(String designId) {
        try {
            if (!designExists(designId)) {
                System.err.println("[ERROR] Design not found: " + designId);
                return false;
            }

            Bson filter = Filters.eq("designId", designId);
            designsCollection.deleteOne(filter);

            System.out.println("[OK] Design deleted from MongoDB: " + designId);
            return true;
        } catch (Exception e) {
            System.err.println("[ERROR] Error deleting design: " + e.getMessage());
            return false;
        }
    }

    // ========== UTILITY METHODS ==========

    /**
     * Check if a design exists
     * 
     * @param designId The design ID
     * @return true if exists, false otherwise
     */
    public boolean designExists(String designId) {
        try {
            Bson filter = Filters.eq("designId", designId);
            return designsCollection.countDocuments(filter) > 0;
        } catch (Exception e) {
            System.err.println("[ERROR] Error checking design existence: " + e.getMessage());
            return false;
        }
    }

    /**
     * Get count of designs for a user
     * 
     * @param userId The owner's user ID
     * @return Number of designs the user has
     */
    public int getDesignCountForUser(String userId) {
        try {
            Bson filter = Filters.eq("userId", userId);
            return (int) designsCollection.countDocuments(filter);
        } catch (Exception e) {
            System.err.println("[ERROR] Error counting designs: " + e.getMessage());
            return 0;
        }
    }

    /**
     * Delete all designs for a specific user (use with caution!)
     * 
     * @param userId The user ID
     * @return Number of designs deleted
     */
    public int deleteAllDesignsForUser(String userId) {
        try {
            Bson filter = Filters.eq("userId", userId);
            long deletedCount = designsCollection.deleteMany(filter).getDeletedCount();
            System.out.println("[WARNING] Deleted " + deletedCount + " designs for user: " + userId);
            return (int) deletedCount;
        } catch (Exception e) {
            System.err.println("[ERROR] Error deleting user designs: " + e.getMessage());
            return 0;
        }
    }

    // ========== SERIALIZATION METHODS ==========

    /**
     * Convert DesignModel to MongoDB Document
     */
    private Document designToDocument(DesignModel design) {
        try {
            Document doc = new Document()
                    .append("_id", design.getDesignId())
                    .append("designId", design.getDesignId())
                    .append("userId", design.getUserId())
                    .append("designName", design.getDesignName())
                    .append("createdAt", convertToDate(design.getCreatedAt()))
                    .append("lastModifiedAt", convertToDate(design.getLastModifiedAt()))
                    .append("tags", design.getTags())
                    .append("notes", design.getNotes())
                    .append("thumbnail", design.getThumbnail());

            // Serialize room
            if (design.getRoom() != null) {
                doc.append("room", roomToDocument(design.getRoom()));
            }

            // Serialize furniture items
            if (design.getFurnitureItems() != null && !design.getFurnitureItems().isEmpty()) {
                List<Document> furnitureDocuments = design.getFurnitureItems().stream()
                        .map(this::furnitureToDocument)
                        .collect(Collectors.toList());
                doc.append("furnitureItems", furnitureDocuments);
            } else {
                doc.append("furnitureItems", new ArrayList<>());
            }

            return doc;
        } catch (Exception e) {
            System.err.println("[ERROR] Error converting design to document: " + e.getMessage());
            e.printStackTrace();
            return null;
        }
    }

    /**
     * Convert MongoDB Document to DesignModel
     */
    private DesignModel documentToDesign(Document doc) {
        try {
            String designId = doc.getString("designId");
            String userId = doc.getString("userId");
            String designName = doc.getString("designName");
            String tags = doc.getString("tags");
            String notes = doc.getString("notes");
            byte[] thumbnail = doc.getObjectId("thumbnail") != null ? 
                    doc.get("thumbnail", byte[].class) : null;

            LocalDateTime createdAt = convertFromDate(doc.getDate("createdAt"));
            LocalDateTime lastModifiedAt = convertFromDate(doc.getDate("lastModifiedAt"));

            // Deserialize room
            Room room = null;
            Document roomDoc = (Document) doc.get("room");
            if (roomDoc != null) {
                room = documentToRoom(roomDoc);
            }

            // Deserialize furniture items
            List<FurnitureItem> furnitureItems = new ArrayList<>();
            List<?> furnitureDocsList = doc.getList("furnitureItems", Document.class);
            if (furnitureDocsList != null) {
                for (Object item : furnitureDocsList) {
                    if (item instanceof Document) {
                        FurnitureItem furniture = documentToFurniture((Document) item);
                        if (furniture != null) {
                            furnitureItems.add(furniture);
                        }
                    }
                }
            }

            return new DesignModel(designId, userId, designName, room, 
                    furnitureItems, createdAt, lastModifiedAt, tags, notes, thumbnail);
        } catch (Exception e) {
            System.err.println("[ERROR] Error converting document to design: " + e.getMessage());
            e.printStackTrace();
            return null;
        }
    }

    /**
     * Convert Room to MongoDB Document
     */
    private Document roomToDocument(Room room) {
        try {
            return new Document()
                    .append("roomId", room.getRoomId())
                    .append("name", room.getName())
                    .append("width", room.getWidth())
                    .append("length", room.getLength())
                    .append("shape", room.getShape().toString())
                    .append("wallColor", colorToString(room.getWallColor()))
                    .append("status", room.getStatus().toString())
                    .append("createdAt", convertToDate(room.getCreatedAt()))
                    .append("lastModifiedAt", convertToDate(room.getLastModifiedAt()));
        } catch (Exception e) {
            System.err.println("[ERROR] Error converting room to document: " + e.getMessage());
            return null;
        }
    }

    /**
     * Convert MongoDB Document to Room
     */
    private Room documentToRoom(Document doc) {
        try {
            String name = doc.getString("name");
            double width = doc.getDouble("width");
            double length = doc.getDouble("length");
            String shapeStr = doc.getString("shape");
            String colorStr = doc.getString("wallColor");

            RoomShape shape = RoomShape.valueOf(shapeStr);
            java.awt.Color color = stringToColor(colorStr);

            return new Room(name, width, length, shape, color);
        } catch (Exception e) {
            System.err.println("[ERROR] Error converting document to room: " + e.getMessage());
            return null;
        }
    }

    /**
     * Convert FurnitureItem to MongoDB Document
     */
    private Document furnitureToDocument(FurnitureItem furniture) {
        try {
            return new Document()
                    .append("name", furniture.getName())
                    .append("type", furniture.getType().toString())
                    .append("imagePath", furniture.getImagePath())
                    .append("width", furniture.getWidth())
                    .append("height", furniture.getHeight())
                    .append("depth", furniture.getDepth())
                    .append("material", furniture.getMaterial())
                    .append("description", furniture.getDescription())
                    .append("x", furniture.getX())
                    .append("y", furniture.getY())
                    .append("rotation", furniture.getRotation())
                    .append("color", colorToString(furniture.getColor()));
        } catch (Exception e) {
            System.err.println("[ERROR] Error converting furniture to document: " + e.getMessage());
            return null;
        }
    }

    /**
     * Convert MongoDB Document to FurnitureItem
     */
    private FurnitureItem documentToFurniture(Document doc) {
        try {
            String name = doc.getString("name");
            String typeStr = doc.getString("type");
            String imagePath = doc.getString("imagePath");
            double width = doc.getDouble("width");
            double height = doc.getDouble("height");
            double depth = doc.getDouble("depth");
            String material = doc.getString("material");
            String description = doc.getString("description");

            FurnitureType type = FurnitureType.valueOf(typeStr);
            FurnitureItem item = new FurnitureItem(name, type, imagePath, width, 
                    height, depth, material, description);

            // Set position and rotation
            item.setX(doc.getDouble("x"));
            item.setY(doc.getDouble("y"));
            item.setRotation(doc.getDouble("rotation"));

            // Set color
            String colorStr = doc.getString("color");
            item.setColor(stringToColor(colorStr));

            return item;
        } catch (Exception e) {
            System.err.println("[ERROR] Error converting document to furniture: " + e.getMessage());
            return null;
        }
    }

    /**
     * Convert LocalDateTime to java.util.Date for MongoDB
     */
    private Date convertToDate(LocalDateTime localDateTime) {
        if (localDateTime == null) return null;
        return Date.from(localDateTime.atZone(ZoneId.systemDefault()).toInstant());
    }

    /**
     * Convert java.util.Date to LocalDateTime
     */
    private LocalDateTime convertFromDate(Date date) {
        if (date == null) return LocalDateTime.now();
        return date.toInstant()
                .atZone(ZoneId.systemDefault())
                .toLocalDateTime();
    }

    /**
     * Convert Color to String for storage
     */
    private String colorToString(java.awt.Color color) {
        if (color == null) return "RGB(150,150,150)";
        return String.format("RGB(%d,%d,%d)", color.getRed(), color.getGreen(), color.getBlue());
    }

    /**
     * Convert String to Color
     */
    private java.awt.Color stringToColor(String colorStr) {
        try {
            if (colorStr == null || colorStr.isEmpty()) {
                return new java.awt.Color(150, 150, 150);
            }
            // Parse "RGB(r,g,b)" format
            colorStr = colorStr.replace("RGB(", "").replace(")", "");
            String[] parts = colorStr.split(",");
            int r = Integer.parseInt(parts[0].trim());
            int g = Integer.parseInt(parts[1].trim());
            int b = Integer.parseInt(parts[2].trim());
            return new java.awt.Color(r, g, b);
        } catch (Exception e) {
            return new java.awt.Color(150, 150, 150);
        }
    }
}

package com.teamname.furniviz.storage;

import java.util.*;
import java.util.stream.Collectors;

/**
 * Design Storage - CRUD operations for user designs
 * 
 * Manages persistence of designs with:
 * - Save/Load/Update/Delete operations
 * - Multi-user filtering (by userId)
 * - Search and filtering capabilities
 * - In-memory HashMap storage (MongoDB integration ready)
 */
public class DesignStorage {

    private static final Map<String, DesignModel> designStore = new HashMap<>();

    public DesignStorage() {
        System.out.println("[INFO] Design Storage initialized");
    }

    // ========== CREATE OPERATION ==========

    /**
     * Save a new design
     * 
     * @param design The design to save
     * @return true if saved successfully, false otherwise
     */
    public boolean saveDesign(DesignModel design) {
        try {
            if (design == null || design.getDesignId() == null) {
                System.err.println("[ERROR] Cannot save null design or design without ID");
                return false;
            }
            designStore.put(design.getDesignId(), design);
            System.out.println("[OK] Design saved: " + design.getDesignId() +
                             " (User: " + design.getUserId() + ", Name: " + design.getDesignName() + ")");
            return true;
        } catch (Exception e) {
            System.err.println("[ERROR] Error saving design: " + e.getMessage());
            e.printStackTrace();
            return false;
        }
    }

    // ========== READ OPERATIONS ==========

    /**
     * Get all designs for a specific user
     * IMPORTANT: Always filter by userId for multi-user support
     * 
     * @param userId The owner's user ID
     * @return List of designs belonging to the user
     */
    public List<DesignModel> getDesignsByUserId(String userId) {
        try {
            List<DesignModel> userDesigns = designStore.values().stream()
                    .filter(design -> design.getUserId().equals(userId))
                    .collect(Collectors.toList());
            System.out.println("[OK] Retrieved " + userDesigns.size() +
                             " designs for user: " + userId);
            return userDesigns;
        } catch (Exception e) {
            System.err.println("[ERROR] Error retrieving designs: " + e.getMessage());
            return new ArrayList<>();
        }
    }

    /**
     * Get a specific design by ID
     * 
     * @param designId The design ID
     * @return The design, or null if not found
     */
    public DesignModel getDesignById(String designId) {
        try {
            DesignModel design = designStore.get(designId);
            if (design == null) {
                System.out.println("[WARNING] Design not found: " + designId);
            } else {
                System.out.println("[OK] Retrieved design: " + designId);
            }
            return design;
        } catch (Exception e) {
            System.err.println("[ERROR] Error retrieving design: " + e.getMessage());
            return null;
        }
    }

    /**
     * Get all designs (admin only - use with caution!)
     * 
     * @return List of all designs
     */
    public List<DesignModel> getAllDesigns() {
        try {
            List<DesignModel> allDesigns = new ArrayList<>(designStore.values());
            System.out.println("[OK] Retrieved all " + allDesigns.size() + " designs");
            return allDesigns;
        } catch (Exception e) {
            System.err.println("[ERROR] Error retrieving all designs: " + e.getMessage());
            return new ArrayList<>();
        }
    }

    /**
     * Search designs by name for a specific user
     * 
     * @param userId The owner's user ID
     * @param searchTerm The search term (case-insensitive)
     * @return List of matching designs
     */
    public List<DesignModel> searchByName(String userId, String searchTerm) {
        try {
            return designStore.values().stream()
                    .filter(d -> d.getUserId().equals(userId))
                    .filter(d -> d.getDesignName().toLowerCase()
                            .contains(searchTerm.toLowerCase()))
                    .collect(Collectors.toList());
        } catch (Exception e) {
            System.err.println("[ERROR] Error searching designs: " + e.getMessage());
            return new ArrayList<>();
        }
    }

    /**
     * Filter designs by tags
     * 
     * @param userId The owner's user ID
     * @param tag The tag to filter by
     * @return List of designs with the tag
     */
    public List<DesignModel> filterByTag(String userId, String tag) {
        try {
            return designStore.values().stream()
                    .filter(d -> d.getUserId().equals(userId))
                    .filter(d -> d.getTags().contains(tag))
                    .collect(Collectors.toList());
        } catch (Exception e) {
            System.err.println("[ERROR] Error filtering by tag: " + e.getMessage());
            return new ArrayList<>();
        }
    }

    // ========== UPDATE OPERATION ==========

    /**
     * Update an existing design
     * 
     * @param design The updated design
     * @return true if updated successfully, false otherwise
     */
    public boolean updateDesign(DesignModel design) {
        try {
            if (!designStore.containsKey(design.getDesignId())) {
                System.err.println("[ERROR] Design not found: " + design.getDesignId());
                return false;
            }
            designStore.put(design.getDesignId(), design);
            System.out.println("[OK] Design updated: " + design.getDesignId() + 
                             " (Name: " + design.getDesignName() + ")");
            return true;
        } catch (Exception e) {
            System.err.println("[ERROR] Error updating design: " + e.getMessage());
            return false;
        }
    }

    // ========== DELETE OPERATION ==========

    /**
     * Delete a design by ID
     * 
     * @param designId The design ID to delete
     * @return true if deleted successfully, false otherwise
     */
    public boolean deleteDesign(String designId) {
        try {
            if (!designStore.containsKey(designId)) {
                System.err.println("[ERROR] Design not found: " + designId);
                return false;
            }
            designStore.remove(designId);
            System.out.println("[OK] Design deleted: " + designId);
            return true;
        } catch (Exception e) {
            System.err.println("[ERROR] Error deleting design: " + e.getMessage());
            return false;
        }
    }

    // ========== UTILITY METHODS ==========

    /**
     * Check if a design exists
     * 
     * @param designId The design ID
     * @return true if exists, false otherwise
     */
    public boolean designExists(String designId) {
        return designStore.containsKey(designId);
    }

    /**
     * Get count of designs for a user
     * 
     * @param userId The owner's user ID
     * @return Number of designs the user has
     */
    public int getDesignCountForUser(String userId) {
        return (int) designStore.values().stream()
                .filter(d -> d.getUserId().equals(userId))
                .count();
    }

    /**
     * Clear all designs (for testing only!)
     */
    public void clearAllDesigns() {
        designStore.clear();
        System.out.println("[WARNING] All designs cleared!");
    }
}

package com.teamname.furniviz.storage;

import java.util.*;
import java.util.stream.Collectors;

/**
 * Design Storage - CRUD operations for user designs
 * 
 * Manages persistence of designs with:
 * - Save/Load/Update/Delete operations
 * - Multi-user filtering (by userId)
 * - Search and filtering capabilities
 * - Permanent MongoDB storage (replaces in-memory HashMap)
 */
public class DesignStorage {

    private DesignRepository designRepository;

    public DesignStorage() {
        this.designRepository = new DesignRepository();
        System.out.println("[INFO] Design Storage initialized with MongoDB backend");
    }

    // ========== CREATE OPERATION ==========

    /**
     * Save a new design
     * 
     * @param design The design to save
     * @return true if saved successfully, false otherwise
     */
    public boolean saveDesign(DesignModel design) {
        return designRepository.saveDesign(design);
    }

    // ========== READ OPERATIONS ==========

    /**
     * Get all designs for a specific user
     * IMPORTANT: Always filter by userId for multi-user support
     * 
     * @param userId The owner's user ID
     * @return List of designs belonging to the user
     */
    public List<DesignModel> getDesignsByUserId(String userId) {
        return designRepository.getDesignsByUserId(userId);
    }

    /**
     * Get a specific design by ID
     * 
     * @param designId The design ID
     * @return The design, or null if not found
     */
    public DesignModel getDesignById(String designId) {
        return designRepository.getDesignById(designId);
    }

    /**
     * Get all designs (admin only - use with caution!)
     * 
     * @return List of all designs
     */
    public List<DesignModel> getAllDesigns() {
        return designRepository.getAllDesigns();
    }

    /**
     * Search designs by name for a specific user
     * 
     * @param userId The owner's user ID
     * @param searchTerm The search term (case-insensitive)
     * @return List of matching designs
     */
    public List<DesignModel> searchByName(String userId, String searchTerm) {
        return designRepository.searchByName(userId, searchTerm);
    }

    /**
     * Filter designs by tags
     * 
     * @param userId The owner's user ID
     * @param tag The tag to filter by
     * @return List of designs with the tag
     */
    public List<DesignModel> filterByTag(String userId, String tag) {
        return designRepository.filterByTag(userId, tag);
    }

    // ========== UPDATE OPERATION ==========

    /**
     * Update an existing design
     * 
     * @param design The updated design
     * @return true if updated successfully, false otherwise
     */
    public boolean updateDesign(DesignModel design) {
        return designRepository.updateDesign(design);
    }

    // ========== DELETE OPERATION ==========

    /**
     * Delete a design by ID
     * 
     * @param designId The design ID to delete
     * @return true if deleted successfully, false otherwise
     */
    public boolean deleteDesign(String designId) {
        return designRepository.deleteDesign(designId);
    }

    // ========== UTILITY METHODS ==========

    /**
     * Check if a design exists
     * 
     * @param designId The design ID
     * @return true if exists, false otherwise
     */
    public boolean designExists(String designId) {
        return designRepository.designExists(designId);
    }

    /**
     * Get count of designs for a user
     * 
     * @param userId The owner's user ID
     * @return Number of designs the user has
     */
    public int getDesignCountForUser(String userId) {
        return designRepository.getDesignCountForUser(userId);
    }

    /**
     * Clear all designs for a user (for testing only!)
     */
    public void clearAllDesignsForUser(String userId) {
        designRepository.deleteAllDesignsForUser(userId);
        System.out.println("[WARNING] All designs cleared for user: " + userId);
    }
}

package com.teamname.furniviz.storage;

import com.google.gson.Gson;
import com.google.gson.GsonBuilder;
import com.teamname.furniviz.room.Room;
import com.teamname.furniviz.room.RoomShape;

import java.awt.Color;
import java.time.LocalDateTime;
import java.time.format.DateTimeFormatter;
import java.util.ArrayList;
import java.util.HashMap;
import java.util.List;
import java.util.Map;

/**
 * Room Repository - CRUD operations for room templates
 * Uses in-memory storage with HashMap (MongoDB integration optional)
 * Handles serialization/deserialization of Room objects
 */
public class RoomRepository {

    private static final String COLLECTION_NAME = "rooms";
    private static final Gson gson = new GsonBuilder().setPrettyPrinting().create();
    // In-memory storage
    private static final Map<String, Room> roomStore = new HashMap<>();

    public RoomRepository() {
        System.out.println("Room Repository initialized with in-memory storage");
    }

    /**
     * Save a new room template
     */
    public boolean saveRoom(Room room) {
        try {
            roomStore.put(room.getRoomId(), room);
            System.out.println("[OK] Room saved: " + room.getRoomId());
            return true;
        } catch (Exception e) {
            System.err.println("[ERROR] Error saving room: " + e.getMessage());
            return false;
        }
    }

    /**
     * Update an existing room template
     */
    public boolean updateRoom(Room room) {
        try {
            roomStore.put(room.getRoomId(), room);
            System.out.println("[OK] Room updated: " + room.getRoomId());
            return true;
        } catch (Exception e) {
            System.err.println("[ERROR] Error updating room: " + e.getMessage());
            return false;
        }
    }

    /**
     * Delete a room template by ID
     */
    public boolean deleteRoom(String roomId) {
        try {
            roomStore.remove(roomId);
            System.out.println("[OK] Room deleted: " + roomId);
            return true;
        } catch (Exception e) {
            System.err.println("[ERROR] Error deleting room: " + e.getMessage());
            return false;
        }
    }

    /**
     * Get all room templates
     */
    public List<Room> getAllRooms() {
        List<Room> rooms = new ArrayList<>();
        try {
            rooms.addAll(roomStore.values());
            System.out.println("[OK] Retrieved " + rooms.size() + " rooms");
        } catch (Exception e) {
            System.err.println("[ERROR] Error retrieving rooms: " + e.getMessage());
        }
        return rooms;
    }

    /**
     * Get a specific room by ID
     */
    public Room getRoomById(String roomId) {
        try {
            return roomStore.get(roomId);
        } catch (Exception e) {
            System.err.println("[ERROR] Error retrieving room: " + e.getMessage());
        }
        return null;
    }

    /**
     * Serialize Room object to JSON string
     */
    public String roomToJson(Room room) {
        return gson.toJson(room);
    }

    /**
     * Deserialize JSON string to Room object
     */
    public Room jsonToRoom(String json) {
        try {
            return gson.fromJson(json, Room.class);
        } catch (Exception e) {
            System.err.println("[ERROR] Error converting JSON to room: " + e.getMessage());
            return null;
        }
    }

    /**
     * Convert Color to String for storage
     */
    private String colorToString(Color color) {
        return String.format("RGB(%d,%d,%d)", color.getRed(), color.getGreen(), color.getBlue());
    }

    /**
     * Convert String to Color
     */
    private Color stringToColor(String colorStr) {
        try {
            // Parse "RGB(r,g,b)" format
            colorStr = colorStr.replace("RGB(", "").replace(")", "");
            String[] parts = colorStr.split(",");
            int r = Integer.parseInt(parts[0].trim());
            int g = Integer.parseInt(parts[1].trim());
            int b = Integer.parseInt(parts[2].trim());
            return new Color(r, g, b);
        } catch (Exception e) {
            return Color.WHITE;
        }
    }

    /**
     * Get count of all rooms
     */
    public long getRoomCount() {
        return roomStore.size();
    }

    /**
     * Delete all rooms (for testing/reset)
     */
    public void deleteAllRooms() {
        try {
            roomStore.clear();
            System.out.println("[OK] All rooms deleted");
        } catch (Exception e) {
            System.err.println("[ERROR] Error deleting all rooms: " + e.getMessage());
        }
    }
}

package com.teamname.furniviz.storage;

import com.google.gson.Gson;
import com.google.gson.GsonBuilder;
import com.mongodb.client.MongoCollection;
import com.mongodb.client.model.Filters;
import com.mongodb.client.model.IndexOptions;
import com.teamname.furniviz.room.Room;
import com.teamname.furniviz.room.RoomShape;
import org.bson.Document;
import org.bson.conversions.Bson;

import java.awt.Color;
import java.time.LocalDateTime;
import java.time.ZoneId;
import java.util.ArrayList;
import java.util.Date;
import java.util.List;

/**
 * Room Repository - MongoDB-backed CRUD operations for room templates
 * 
 * Replaces in-memory HashMap with permanent MongoDB storage
 * Handles serialization/deserialization of Room objects
 */
public class RoomRepository {

    private static final String COLLECTION_NAME = "rooms";
    private static final Gson gson = new GsonBuilder().setPrettyPrinting().create();
    private MongoCollection<Document> roomsCollection;

    public RoomRepository() {
        MongoDBConnection connection = MongoDBConnection.getInstance();
        this.roomsCollection = connection.getCollection(COLLECTION_NAME);
        ensureCollectionsExist();
    }

    /**
     * Ensure rooms collection exists with proper indexes
     */
    public void ensureCollectionsExist() {
        try {
            // Create unique index on roomId field
            roomsCollection.createIndex(
                    new Document("roomId", 1),
                    new IndexOptions().unique(true)
            );
            System.out.println("[OK] Rooms collection ready with unique roomId index");
        } catch (Exception e) {
            System.out.println("[INFO] Rooms collection/indexes already exist");
        }
    }

    /**
     * Save a new room template to MongoDB
     */
    public boolean saveRoom(Room room) {
        try {
            if (room == null || room.getRoomId() == null) {
                System.err.println("[ERROR] Cannot save null room or room without ID");
                return false;
            }

            Document roomDoc = roomToDocument(room);
            roomsCollection.insertOne(roomDoc);
            System.out.println("[OK] Room saved to MongoDB: " + room.getRoomId() + " (" + room.getName() + ")");
            return true;
        } catch (com.mongodb.MongoWriteException e) {
            if (e.getError().getCategory().toString().contains("DUPLICATE")) {
                System.err.println("[ERROR] Room already exists: " + room.getRoomId());
            } else {
                System.err.println("[ERROR] Error saving room: " + e.getMessage());
            }
            return false;
        } catch (Exception e) {
            System.err.println("[ERROR] Error saving room: " + e.getMessage());
            e.printStackTrace();
            return false;
        }
    }

    /**
     * Update an existing room template in MongoDB
     */
    public boolean updateRoom(Room room) {
        try {
            if (!roomExists(room.getRoomId())) {
                System.err.println("[ERROR] Room not found: " + room.getRoomId());
                return false;
            }

            Bson filter = Filters.eq("roomId", room.getRoomId());
            Document roomDoc = roomToDocument(room);
            roomsCollection.replaceOne(filter, roomDoc);

            System.out.println("[OK] Room updated in MongoDB: " + room.getRoomId());
            return true;
        } catch (Exception e) {
            System.err.println("[ERROR] Error updating room: " + e.getMessage());
            e.printStackTrace();
            return false;
        }
    }

    /**
     * Delete a room template by ID from MongoDB
     */
    public boolean deleteRoom(String roomId) {
        try {
            if (!roomExists(roomId)) {
                System.err.println("[ERROR] Room not found: " + roomId);
                return false;
            }

            Bson filter = Filters.eq("roomId", roomId);
            roomsCollection.deleteOne(filter);

            System.out.println("[OK] Room deleted from MongoDB: " + roomId);
            return true;
        } catch (Exception e) {
            System.err.println("[ERROR] Error deleting room: " + e.getMessage());
            return false;
        }
    }

    /**
     * Get all room templates from MongoDB
     */
    public List<Room> getAllRooms() {
        List<Room> rooms = new ArrayList<>();
        try {
            for (Document doc : roomsCollection.find()) {
                Room room = documentToRoom(doc);
                if (room != null) {
                    rooms.add(room);
                }
            }
            System.out.println("[OK] Retrieved " + rooms.size() + " rooms from MongoDB");
        } catch (Exception e) {
            System.err.println("[ERROR] Error retrieving rooms: " + e.getMessage());
        }
        return rooms;
    }

    /**
     * Get a specific room by ID from MongoDB
     */
    public Room getRoomById(String roomId) {
        try {
            Bson filter = Filters.eq("roomId", roomId);
            Document doc = roomsCollection.find(filter).first();

            if (doc == null) {
                System.out.println("[WARNING] Room not found: " + roomId);
                return null;
            }

            Room room = documentToRoom(doc);
            System.out.println("[OK] Retrieved room: " + roomId);
            return room;
        } catch (Exception e) {
            System.err.println("[ERROR] Error retrieving room: " + e.getMessage());
            return null;
        }
    }

    /**
     * Serialize Room object to MongoDB Document
     */
    private Document roomToDocument(Room room) {
        try {
            return new Document()
                    .append("_id", room.getRoomId())
                    .append("roomId", room.getRoomId())
                    .append("name", room.getName())
                    .append("width", room.getWidth())
                    .append("length", room.getLength())
                    .append("shape", room.getShape().toString())
                    .append("wallColor", colorToString(room.getWallColor()))
                    .append("status", room.getStatus().toString())
                    .append("createdAt", convertToDate(room.getCreatedAt()))
                    .append("lastModifiedAt", convertToDate(room.getLastModifiedAt()));
        } catch (Exception e) {
            System.err.println("[ERROR] Error converting room to document: " + e.getMessage());
            return null;
        }
    }

    /**
     * Deserialize MongoDB Document to Room object
     */
    private Room documentToRoom(Document doc) {
        try {
            String name = doc.getString("name");
            double width = doc.getDouble("width");
            double length = doc.getDouble("length");
            String shapeStr = doc.getString("shape");
            String colorStr = doc.getString("wallColor");

            RoomShape shape = RoomShape.valueOf(shapeStr);
            Color color = stringToColor(colorStr);

            Room room = new Room(name, width, length, shape, color);
            room.setStatus(Room.RoomStatus.valueOf(doc.getString("status")));

            return room;
        } catch (Exception e) {
            System.err.println("[ERROR] Error converting document to room: " + e.getMessage());
            return null;
        }
    }

    /**
     * Convert Color to String for storage
     */
    private String colorToString(Color color) {
        if (color == null) return "RGB(255,255,255)";
        return String.format("RGB(%d,%d,%d)", color.getRed(), color.getGreen(), color.getBlue());
    }

    /**
     * Convert String to Color
     */
    private Color stringToColor(String colorStr) {
        try {
            if (colorStr == null || colorStr.isEmpty()) {
                return Color.WHITE;
            }
            // Parse "RGB(r,g,b)" format
            colorStr = colorStr.replace("RGB(", "").replace(")", "");
            String[] parts = colorStr.split(",");
            int r = Integer.parseInt(parts[0].trim());
            int g = Integer.parseInt(parts[1].trim());
            int b = Integer.parseInt(parts[2].trim());
            return new Color(r, g, b);
        } catch (Exception e) {
            return Color.WHITE;
        }
    }

    /**
     * Convert LocalDateTime to java.util.Date for MongoDB
     */
    private Date convertToDate(LocalDateTime localDateTime) {
        if (localDateTime == null) return null;
        return Date.from(localDateTime.atZone(ZoneId.systemDefault()).toInstant());
    }

    /**
     * Check if a room exists
     */
    public boolean roomExists(String roomId) {
        try {
            Bson filter = Filters.eq("roomId", roomId);
            return roomsCollection.countDocuments(filter) > 0;
        } catch (Exception e) {
            System.err.println("[ERROR] Error checking room existence: " + e.getMessage());
            return false;
        }
    }

    /**
     * Get count of all rooms
     */
    public long getRoomCount() {
        try {
            return roomsCollection.countDocuments();
        } catch (Exception e) {
            System.err.println("[ERROR] Error counting rooms: " + e.getMessage());
            return 0;
        }
    }

    /**
     * Delete all rooms (for testing/reset)
     */
    public void deleteAllRooms() {
        try {
            roomsCollection.deleteMany(new Document());
            System.out.println("[OK] All rooms deleted from MongoDB");
        } catch (Exception e) {
            System.err.println("[ERROR] Error deleting all rooms: " + e.getMessage());
        }
    }

    /**
     * Serialize Room object to JSON string (for export/backup)
     */
    public String roomToJson(Room room) {
        return gson.toJson(room);
    }

    /**
     * Deserialize JSON string to Room object
     */
    public Room jsonToRoom(String json) {
        try {
            return gson.fromJson(json, Room.class);
        } catch (Exception e) {
            System.err.println("[ERROR] Error converting JSON to room: " + e.getMessage());
            return null;
        }
    }
}
